## new的优化技巧

```javascript
// 使用new创建对象比对象字面量稍慢
const obj = {};  // 推荐

const obj2 = new Object(); // 不推荐（多一次函数调用）

// 对于频繁创建对象的场景，考虑对象池
class ObjectPool {
  constructor(factory, size = 100) {
    this.factory = factory;
    this.pool = [];
    for (let i = 0; i < size; i++) {
      this.pool.push(new factory());
    }
  }
  acquire() {
    return this.pool.pop() || new this.factory();
  }
  release(obj) {
    this.pool.push(obj);
  }
}
```

# ✅requestAnimationFrame和requestIdleCallback的区别

# 典型回答

`requestAnimationFrame` 和 `requestIdleCallback` 是浏览器提供的两个用于调度回调的API，但它们的用途和执行时机完全不同：

| 特性 | requestAnimationFrame | requestIdleCallback |
|------|---------------------|-------------------|
| 执行时机 | 浏览器**每次重绘前** | 浏览器**空闲时期** |
| 执行频率 | 约60fps（与屏幕刷新率同步） | 不确定，取决于空闲时间 |
| 优先级 | **高**（渲染关键） | **低**（后台任务） |
| 回调参数 | DOMHighResTimeStamp（时间戳） | IdleDeadline（包含剩余时间和是否超时） |
| 主要用途 | 动画、DOM更新、视觉变化 | 非紧急任务、数据上报、预计算 |
| 对性能的影响 | 可能导致掉帧 | 不阻塞主线程 |
| 是否强制等待 | 是，一定会在渲染前执行 | 否，浏览器可能不调用回调 |

**核心区别：**
- `requestAnimationFrame`：**"我需要在下一次渲染前执行这个"** — 用于视觉更新
- `requestIdleCallback`：**"浏览器有空时再执行这个"** — 用于非紧急后台任务

# 扩展知识

## requestAnimationFrame 详解

```javascript
// 基本的动画循环
function animate(timestamp) {
  // timestamp: 从页面加载开始的高精度时间戳（毫秒）
  element.style.left = Math.sin(timestamp / 1000) * 100 + 'px';

  // 继续下一帧动画
  animationId = requestAnimationFrame(animate);
}

const animationId = requestAnimationFrame(animate);

// 取消动画
// cancelAnimationFrame(animationId);
```

## requestAnimationFrame 的优势

```javascript
// 1. 自动与屏幕刷新率同步（60Hz/120Hz）
// 2. 页面不可见时自动暂停（节省CPU/电池）
// 3. 动画更平滑（在渲染之前执行）

// 与setTimeout对比
let start = Date.now();

// setTimeout动画
function setTimeoutAnim() {
  const elapsed = Date.now() - start;
  element.style.left = Math.min(elapsed / 10, 200) + 'px';
  if (elapsed < 2000) setTimeout(setTimeoutAnim, 16); // 模拟60fps
}
// 问题：可能掉帧、后台继续运行

// requestAnimationFrame动画
function rAFAnim(timestamp) {
  const elapsed = timestamp - startTime;
  element.style.left = Math.min(elapsed / 10, 200) + 'px';
  if (elapsed < 2000) requestAnimationFrame(rAFAnim);
}
const startTime = performance.now();
requestAnimationFrame(rAFAnim);
// 优点：平滑、自动暂停、省电

// 实际应用：实现帧率独立的动画
function frameRateIndependent(deltaTime) {
  // deltaTime是两帧之间的时间差
  speed = 100; // 像素/秒
  position += speed * (deltaTime / 1000);
}
```

## requestIdleCallback 详解

```javascript
// 基本使用
function myIdleCallback(deadline) {
  // deadline.timeRemaining() — 剩余空闲时间（毫秒）
  // deadline.didTimeout — 是否因超时而执行

  while (deadline.timeRemaining() > 0 && tasks.length > 0) {
    const task = tasks.shift();
    process(task); // 执行一个任务
  }

  if (tasks.length > 0) {
    // 还有任务没完成，下次空闲继续
    requestIdleCallback(myIdleCallback);
  }
}

requestIdleCallback(myIdleCallback);

// 注意：浏览器可能根本不调用回调（没有空闲时间）
// 可以选择设置超时
requestIdleCallback(myIdleCallback, { timeout: 2000 });
// 如果2000ms内浏览器都没有空闲，会强制执行回调
```

## requestIdleCallback 的应用场景

```javascript
// 1. 数据上报（非关键）
function scheduleReport(data) {
  requestIdleCallback(() => {
    navigator.sendBeacon('/api/report', data);
  }, { timeout: 5000 });
}

// 2. 预计算/预渲染
function prepareForNextPage() {
  requestIdleCallback(() => {
    // 预先编译模板
    const template = compileTemplate(nextPageTemplate);
    // 预计算复杂样式
    precomputeStyles();
  });
}

// 3. 大型数据的分片处理
function processLargeArray(data) {
  let index = 0;

  function processChunk(deadline) {
    while (deadline.timeRemaining() > 5 && index < data.length) {
      // 分批处理数据
      const item = data[index++];
      const processed = heavyProcess(item);
      results.push(processed);
    }

    if (index < data.length) {
      requestIdleCallback(processChunk);
    } else {
      onComplete(results);
    }
  }

  requestIdleCallback(processChunk);
}

// 4. 惰性加载非关键资源
function lazyLoadNonCritical() {
  requestIdleCallback(() => {
    // 加载非关键图片
    const images = document.querySelectorAll('[data-lazy="true"]');
    images.forEach(img => {
      img.src = img.dataset.src;
    });
  });
}
```

## 两者的对比实验

```javascript
// 模拟一个需要大量计算的场景
function measureExecutionTime() {
  const data = Array.from({ length: 1000 }, (_, i) => i);

  // requestAnimationFrame中执行
  requestAnimationFrame(() => {
    const start = performance.now();
    data.forEach(i => heavyComputation(i));
    const elapsed = performance.now() - start;
    console.log(`rAF: 阻塞${elapsed}ms`); // 会导致掉帧
  });

  // requestIdleCallback中执行
  requestIdleCallback((deadline) => {
    const start = performance.now();
    while (deadline.timeRemaining() > 0) {
      // 分片处理
    }
    const elapsed = performance.now() - start;
    console.log(`rIC: 使用${elapsed}ms空闲时间`); // 不阻塞渲染
  });
}

function heavyComputation(n) {
  let result = 0;
  for (let i = 0; i < 10000; i++) {
    result += Math.sqrt(n * i);
  }
  return result;
}
```

## 三者对比：setTimeout vs rAF vs rIC

```javascript
// 执行时机图
// ----[宏任务]----[微任务]----[requestAnimationFrame]----[渲染]----[requestIdleCallback]----

// 测试代码
console.log('1: 同步代码');

setTimeout(() => console.log('2: setTimeout'), 0);

requestAnimationFrame(() => {
  console.log('3: requestAnimationFrame');
});

requestIdleCallback(() => {
  console.log('4: requestIdleCallback');
});

console.log('5: 同步代码结束');

// 通常输出顺序：
// 1, 5, 2 或 3, 4
// 注意：rAF可能在setTimeout之前或之后，取决于浏览器实现
// rIC通常在下一帧的空闲时间执行
```

## 浏览器兼容性与Polyfill

```javascript
// requestIdleCallback的兼容性不如requestAnimationFrame好
// Safari不支持requestIdleCallback

// 简单的polyfill（使用setTimeout模拟）
if (typeof requestIdleCallback === 'undefined') {
  window.requestIdleCallback = function(callback) {
    const start = Date.now();
    return setTimeout(function() {
      callback({
        didTimeout: false,
        timeRemaining: function() {
          return Math.max(0, 50 - (Date.now() - start));
        }
      });
    }, 1);
  };

  window.cancelIdleCallback = function(id) {
    clearTimeout(id);
  };
}
```

## 实际应用选择指南

| 场景 | 推荐API | 原因 |
|------|--------|------|
| DOM动画/过渡 | rAF | 与渲染同步，平滑 |
| Canvas/SVG动画 | rAF | 高帧率要求 |
| 滚动监听更新 | rAF | 避免滚动卡顿 |
| 非关键数据上报 | rIC | 不阻塞交互 |
| 大数据分批处理 | rIC | 利用空闲时间 |
| 预加载/预计算 | rIC | 后台执行 |
| 需要即时执行 | setTimeout | 尽快执行但不阻塞 |
| 代码统计分析 | rIC | 非关键、可延迟 |
| 无障碍通知 | rAF | 需要及时更新 |

# ✅setTimeout和setInterval的精度问题

# 典型回答

`setTimeout` 和 `setInterval` 的**计时精度并不准确**，它们只是**将回调添加到任务队列**，不能保证在指定的时间后精确执行。

**精度问题的核心原因：**

| 原因 | 说明 |
|------|------|
| 事件循环机制 | 定时器回调是宏任务，必须等当前任务和微任务队列清空后才会执行 |
| 最小延迟限制 | 浏览器强制最小延迟（嵌套5层后至少4ms） |
| 页面状态影响 | 后台标签页、节流模式会降低定时器频率 |
| 系统负载 | CPU繁忙时，定时器精度下降 |
| 时间漂移 | setInterval的累积误差 |

**最小延迟限制：**
- HTML5规范：嵌套层数超过5层的 `setTimeout`，最小延迟为4ms
- 未激活的标签页中，定时器会被节流（通常至少1000ms）

# 扩展知识

## setTimeout的精度演示

```javascript
console.time('setTimeout');

setTimeout(() => {
  console.timeEnd('setTimeout'); // 通常不是精确的0ms
}, 0);

// 即使延迟设为0，实际执行时间也取决于队列中的任务

// 被阻塞的情况
const start = Date.now();

setTimeout(() => {
  console.log('实际延迟:', Date.now() - start, 'ms');
}, 100);

// 一个长时间运行的任务
const blockEnd = Date.now() + 500;
while (Date.now() < blockEnd) {
  // 阻塞主线程500ms
}

// 输出：实际延迟: 约500ms（不是100ms）
// 因为定时器回调在循环执行完之前无法执行
```

## setInterval的累积误差

```javascript
// setInterval的经典问题：执行时间累积误差
let count = 0;
const startTime = Date.now();

const interval = setInterval(() => {
  count++;
  const elapsed = Date.now() - startTime;
  const expected = count * 100;
  const drift = elapsed - expected;

  console.log(`第${count}次: 期望${expected}ms, 实际${elapsed}ms, 偏差${drift}ms`);

  // 模拟耗时操作
  const blockEnd = Date.now() + 50;
  while (Date.now() < blockEnd) {}

  if (count >= 10) clearInterval(interval);
}, 100);

// setInterval不会等待回调执行完毕再开始下一次计时
// 如果回调执行时间 > 间隔时间，会出现连续无间隔执行
```

## 使用setTimeout模拟setInterval

```javascript
// 更精确的定时执行：使用递归setTimeout
function preciseInterval(fn, delay) {
  let timerId;
  let expected = Date.now() + delay;

  function step() {
    const drift = Date.now() - expected;
    fn(drift);  // 传入偏差值

    expected += delay;
    // 根据偏差调整下一次等待时间
    timerId = setTimeout(step, Math.max(0, delay - drift));
  }

  timerId = setTimeout(step, delay);
  return () => clearTimeout(timerId);
}

// 使用
const cancel = preciseInterval((drift) => {
  console.log(`执行，偏差: ${drift}ms`);
}, 1000);

// 停止
// cancel();
```

## 页面可见性对定时器的影响

```javascript
// 页面隐藏时，浏览器会节流定时器
document.addEventListener('visibilitychange', () => {
  if (document.hidden) {
    console.log('页面隐藏，定时器将被节流');
  }
});

// 测试
let countHidden = 0;
let intervalId = setInterval(() => {
  countHidden++;
  console.log(`间隔执行 #${countHidden}`);
}, 100);

// 切换到其他标签页后：
// - Chrome: 定时器被限制为每秒最多1次
// - Firefox: 与Chrome类似
// - Safari: 更严格的限制

// Node.js中没有此限制
```

## requestAnimationFrame替代方案

```javascript
// 动画场景中，用requestAnimationFrame替代setTimeout/setInterval
function animateWithTimeout() {
  let position = 0;
  const interval = setInterval(() => {
    position += 5;
    element.style.transform = `translateX(${position}px)`;
    if (position >= 500) clearInterval(interval);
  }, 16); // 约60fps
}

// 更好的方案
function animateWithRAF() {
  let position = 0;
  let lastTime = performance.now();

  function step(currentTime) {
    const deltaTime = currentTime - lastTime;
    lastTime = currentTime;

    // 基于时间差的动画（帧率无关）
    position += (deltaTime / 16) * 5; // 基于60fps调整
    element.style.transform = `translateX(${position}px)`;

    if (position < 500) {
      requestAnimationFrame(step);
    }
  }

  requestAnimationFrame(step);
}
```

## 高精度计时方案

```javascript
// 需要高精度计时时的备选方案
// 1. performance.now() — 微秒级精度（不受系统时间影响）
const startPerf = performance.now();
setTimeout(() => {
  const elapsed = performance.now() - startPerf;
  console.log(`实际耗时: ${elapsed.toFixed(3)}ms`);
}, 1000);

// 2. Date.now() — 毫秒级精度（受系统时间影响）
const startDate = Date.now();
setTimeout(() => {
  const elapsed = Date.now() - startDate;
  console.log(`实际耗时: ${elapsed}ms`);
}, 1000);

// 3. Web Worker中的定时器（不受主线程阻塞）
// main.js
const worker = new Worker('timer-worker.js');
worker.postMessage({ type: 'start', interval: 100 });
worker.onmessage = (e) => {
  console.log('Worker计时:', e.data);
};

// timer-worker.js
self.onmessage = (e) => {
  if (e.data.type === 'start') {
    setInterval(() => {
      self.postMessage(Date.now());
    }, e.data.interval);
  }
};
```

