## 定时器精度问题的影响

```javascript
// 1. 游戏循环 — 不能依赖setInterval
// 差方案
setInterval(() => {
  updateGameState(); // 精度不够，导致卡顿或加速
  render();
}, 16);

// 好方案
let lastTime = performance.now();
function gameLoop(currentTime) {
  const delta = currentTime - lastTime;
  lastTime = currentTime;

  updateGameState(delta); // 基于时间差更新
  render();

  requestAnimationFrame(gameLoop);
}
requestAnimationFrame(gameLoop);

// 2. 倒计时 — 累积误差需要修正
function countdown(duration, onTick, onComplete) {
  const start = Date.now();
  let remaining = duration;

  function tick() {
    const elapsed = Date.now() - start;
    remaining = Math.max(0, duration - elapsed);

    onTick(remaining);

    if (remaining > 0) {
      // 修正下一次调用的时间
      setTimeout(tick, Math.min(1000, remaining % 1000 || 1000));
    } else {
      onComplete();
    }
  }

  setTimeout(tick, Math.min(1000, remaining % 1000 || 1000));
}

// 使用
countdown(10000,
  (remaining) => console.log(`剩余: ${Math.ceil(remaining / 1000)}秒`),
  () => console.log('倒计时结束')
);
```

## 最佳实践

| 场景 | 推荐方案 |
|------|---------|
| 动画 | requestAnimationFrame |
| 精确间隔执行 | 递归setTimeout + 时间修正 |
| 倒计时 | 基于Date.now()修正 |
| 非精确定时 | setTimeout/setInterval |
| 尽快执行 | queueMicrotask / setImmediate |
| 后台定时 | Web Worker |
| 高精度测量 | performance.now() |

# ✅this的绑定规则有哪些？

# 典型回答

JavaScript中 `this` 的绑定规则有五种，优先级从低到高：

| 规则 | 绑定规则 | 优先级 |
|------|---------|:------:|
| 默认绑定 | 独立函数调用，this指向全局对象（非严格模式）或undefined（严格模式） | 5（最低） |
| 隐式绑定 | 作为对象方法调用，this指向调用该方法的对象 | 4 |
| 显式绑定 | 通过call/apply/bind手动指定this | 3 |
| new绑定 | 通过new调用构造函数，this指向新创建的对象 | 2 |
| 箭头函数绑定 | 箭头函数没有自己的this，继承外层作用域的this | 1（最高，不可覆盖） |

**优先级总结：** `箭头函数 > new绑定 > 显式绑定 > 隐式绑定 > 默认绑定`

# 扩展知识

## 默认绑定

```javascript
// 非严格模式：this指向全局对象（浏览器中的window，Node.js中的global）
function sayHello() {
  console.log(this.name);
}

var name = 'Global';  // var声明会挂在全局对象上

sayHello(); // 'Global'

// 严格模式：this为undefined
function strictHello() {
  'use strict';
  console.log(this); // undefined
  console.log(this.name); // TypeError: Cannot read property 'name' of undefined
}

function wrapping() {
  'use strict';
  sayHello(); // 'Global' — this的指向取决于函数的调用位置，不是定义位置
}

// let/const不会挂在全局对象上
let nameLet = 'Let Name';
sayHello(); // 'Global'（不是'Let Name'）
```

## 隐式绑定

```javascript
const obj = {
  name: 'Object',
  sayName() {
    console.log(this.name);
  }
};

obj.sayName(); // 'Object' — this指向obj

// 隐式丢失
const fn = obj.sayName;
fn(); // undefined（或全局对象上的name）— this丢失，变为默认绑定

// 更隐蔽的丢失
function execute(fn) {
  fn();
}
execute(obj.sayName); // undefined — 传参也是隐式赋值

// 对象链中的this
const obj1 = {
  name: 'obj1',
  inner: {
    name: 'inner',
    sayName() {
      console.log(this.name);
    }
  }
};

obj1.inner.sayName(); // 'inner' — this指向最后一层对象
```

## 显式绑定

```javascript
function greet() {
  console.log(`Hello, ${this.name}`);
}

const user1 = { name: 'Alice' };
const user2 = { name: 'Bob' };

// call — 立即调用，逐个传参
greet.call(user1);  // 'Hello, Alice'

// apply — 立即调用，数组传参
greet.apply(user2); // 'Hello, Bob'

// bind — 返回新函数，永久绑定this
const boundGreet = greet.bind(user1);
boundGreet();               // 'Hello, Alice'
boundGreet.call(user2);     // 'Hello, Alice' — bind过的函数this不可改变

// 硬绑定
function hardBind(fn, ctx) {
  return function(...args) {
    return fn.apply(ctx, args);
  };
}

const bound = hardBind(greet, user1);
bound(); // 'Hello, Alice'
```

## new绑定

```javascript
function Person(name) {
  this.name = name;
  this.sayName = function() {
    console.log(this.name);
  };
}

const p = new Person('Alice');
p.sayName(); // 'Alice'

// new绑定的优先级高于隐式绑定
const obj = {
  create: Person
};

const p2 = new obj.create('Bob');
console.log(p2.name);  // 'Bob'
// 如果是隐式绑定，this指向obj，但new绑定优先级更高

// new绑定高于显式绑定？
function Foo() {
  console.log(this);
}

const foo = Foo.bind({ bound: true });
new foo(); // {}（新创建的对象），bind绑定的this被忽略
// new绑定的优先级高于bind
```

## 箭头函数绑定

```javascript
// 箭头函数不绑定this，继承外层作用域的this
const obj = {
  name: 'obj',
  normal: function() {
    console.log(this.name);
  },
  arrow: () => {
    console.log(this.name);
  }
};

obj.normal(); // 'obj' — 隐式绑定
obj.arrow();  // undefined（全局）— 继承外层的this

// 箭头函数中的this无法被改变
const arrowFn = () => console.log(this);
arrowFn.call({ x: 1 });   // 仍然是外层的this
arrowFn.apply({ x: 1 });  // 同上
arrowFn.bind({ x: 1 })(); // 同上

// 箭头函数在回调中的优势
function Timer() {
  this.seconds = 0;

  // 普通函数：需要额外处理
  setInterval(function() {
    this.seconds++; // this指向window
  }, 1000);

  // 解决方案1：箭头函数
  setInterval(() => {
    this.seconds++; // this指向Timer实例
  }, 1000);
}
```

## 综合优先级测试

```javascript
function testThis() {
  console.log(this.name);
}

const ctx = { name: 'context' };
const bound = testThis.bind(ctx);

// 优先级：new绑定 > bind
const obj = new bound();
console.log(obj instanceof testThis); // true

// 特殊场景：bind函数被new调用时的行为
function bind(fn, ctx) {
  const boundFn = function(...args) {
    // 如果通过new调用，this是新创建的对象，忽略ctx
    return fn.apply(
      new.target ? this : ctx,
      args
    );
  };
  boundFn.prototype = fn.prototype;
  return boundFn;
}
```

## 绑定规则判断流程

```javascript
function determineThis(context) {
  // 1. 函数是箭头函数？ → 继承外层this
  // 2. 通过new调用？ → 新创建的对象
  // 3. 通过call/apply/bind？ → 指定对象
  // 4. 作为对象方法调用？ → 调用对象
  // 5. 默认规则：严格模式 → undefined，非严格模式 → 全局对象
}

// 实战判断
const obj = {
  name: 'obj',
  say: function() {
    const inner = () => console.log(this.name);
    inner();
  }
};

obj.say(); // 'obj'
// say的this由隐式绑定指向obj
// 箭头函数inner继承say的this

const extracted = obj.say;
extracted(); // undefined — say的this丢失，变为默认绑定
// 箭头函数inner继承的是say的this（现在是全局/undefined）
```

## 常见面试题

```javascript
// 面试题1
var name = 'window';
const obj = {
  name: 'obj',
  method: function() {
    console.log(this.name);
    return function() {
      console.log(this.name);
    };
  }
};

obj.method()(); // 'obj' 然后 'window'
// obj.method() — 隐式绑定 → 'obj'
// 返回的函数独立调用 — 默认绑定 → 'window'

// 面试题2
const obj2 = {
  name: 'obj2',
  fn: () => {
    console.log(this.name);
  }
};
obj2.fn(); // window.name — 箭头函数的this在定义时确定，不是调用时

// 面试题3
const person = {
  name: 'person',
  greet: function() {
    setTimeout(() => {
      console.log(this.name);
    }, 100);
  }
};
person.greet(); // 'person' — 箭头函数继承greet的this
```

# ✅var、let、const的作用域区别

# 典型回答

`var`、`let`、`const`是JavaScript中三种声明变量的方式，它们的作用域规则完全不同：

| 维度 | var | let | const |
|------|-----|-----|-------|
| 作用域 | 函数级作用域 | 块级作用域 | 块级作用域 |
| 变量提升 | 声明提升，初始化为undefined | 声明提升，但未初始化（TDZ） | 声明提升，但未初始化（TDZ） |
| 重复声明 | 允许在同一作用域重复声明 | 不允许重复声明 | 不允许重复声明 |
| 重新赋值 | 允许 | 允许 | 不允许（引用不可变） |
| 全局声明 | 成为window/global属性 | 不会成为全局对象属性 | 不会成为全局对象属性 |
| 暂时性死区 | 无 | 有 | 有 |
| 块级作用域 | 不支持（if/for/while中的var会泄露） | 支持 | 支持 |

# 扩展知识

## 函数级作用域 vs 块级作用域

```javascript
// var：函数级作用域，只在函数边界限制
function fn() {
  var a = 1;
  if (true) {
    var a = 2;  // 同个函数作用域，覆盖了外层的a
    console.log(a); // 2
  }
  console.log(a); // 2 — var没有块级作用域限制
}
fn();
// console.log(a); // ReferenceError — 函数边界仍然有效

// let/const：块级作用域
function fn2() {
  let b = 1;
  if (true) {
    let b = 2;  // 独立的块级作用域
    console.log(b); // 2
  }
  console.log(b); // 1 — 块级作用域保护了外部变量
}
```

## var的常见陷阱

```javascript
// 1. 循环变量泄露
for (var i = 0; i < 5; i++) {
  // ...
}
console.log(i); // 5 — i泄露到外部

// 2. if语句中的变量泄露
if (true) {
  var leaked = '我泄露了';
}
console.log(leaked); // '我泄露了'

// 3. switch语句中的变量泄露
switch (1) {
  case 1:
    var caseVar = 'switch中的var';
    break;
}
console.log(caseVar); // 'switch中的var'

// 4. 重复声明没有警告
var name = 'Alice';
var name = 'Bob';  // 覆盖，不报错
console.log(name); // 'Bob'
```

## 块级作用域的覆盖范围

```javascript
// 哪些花括号创建块级作用域？
// 1. if语句
if (true) {
  let x = 1;
}
// console.log(x); // ReferenceError

// 2. for/while循环
for (let i = 0; i < 3; i++) {
  // i仅在循环体内有效
}
// console.log(i); // ReferenceError

// 3. switch语句
switch (1) {
  case 1:
    let y = 1;  // 正常
    break;
  case 2:
    // let y = 2; // SyntaxError: 标识符'y'已被声明
    break;
}
// 建议用花括号包裹每个case
switch (1) {
  case 1: {
    let y = 1;
    break;
  }
  case 2: {
    let y = 2;
    break;
  }
}

// 4. try/catch
try {
  let errorVar = 'try';
} catch (e) {
  let errorVar = 'catch';
}
// console.log(errorVar); // ReferenceError

// 5. 独立的块
{
  let blockVar = '块级';
  const blockConst = '块级常量';
  var stillGlobal = '仍然全局';
}
```

## 三种声明方式的选择策略

```javascript
// 现代JavaScript编码规范：
// 1. 默认使用 const — 所有不需要重新赋值的变量
const MAX_SIZE = 100;
const config = { theme: 'dark' };
const users = [];

// 2. 需要重新赋值时用 let
let count = 0;
let currentUser = null;
for (let i = 0; i < 10; i++) { }

// 3. 绝不使用 var（除非维护老旧代码）

// 为什么不用var？
// - 作用域不明确，容易造成bug
// - 变量提升导致代码可读性差
// - 重复声明不能及时发现错误
// - 块级作用域缺失
```

## 全局声明差异

```javascript
// var 声明全局变量
var globalVar = 'global';
console.log(window.globalVar); // 'global' — 成为window属性

// let/const 声明全局变量
let globalLet = 'let global';
const globalConst = 'const global';
console.log(window.globalLet);   // undefined
console.log(window.globalConst); // undefined

// 影响：var可能意外覆盖全局对象的现有属性
var name = 'myName';  // window.name 是已存在的属性！
console.log(window.name); // 'myName' — 覆盖了默认的window.name
```

## 暂时性死区（TDZ）的深入理解

```javascript
// TDZ指的是从进入作用域到声明完成之间的区域
{
  // TDZ开始
  // console.log(val); // ReferenceError
  let val = 1;
  // TDZ结束
  console.log(val); // 1
}

// typeof 在TDZ中也不安全
typeof notDeclared;    // 'undefined' — 未声明变量是安全的
typeof x;              // ReferenceError — TDZ中的变量
let x;

// TDZ与函数参数默认值
function test(a = b, b = 1) {
  // 参数a的默认值b处于TDZ
}
// test(); // ReferenceError: Cannot access 'b' before initialization

// 正确的顺序
function test(a = 1, b = a) {
  console.log(a, b); // 1, 1
}
test();
```

## for循环中的特殊行为

```javascript
// var在for循环中：共享同一个变量
const funcsVar = [];
for (var i = 0; i < 3; i++) {
  funcsVar.push(() => console.log(i));
}
funcsVar[0](); // 3
funcsVar[1](); // 3
funcsVar[2](); // 3

// let在for循环中：每次迭代创建新的绑定
const funcsLet = [];
for (let i = 0; i < 3; i++) {
  funcsLet.push(() => console.log(i));
}
funcsLet[0](); // 0
funcsLet[1](); // 1
funcsLet[2](); // 2

// 底层原理：for循环的let每次迭代会创建新的词法环境
// 类似于以下效果：
{
  let i = 0;
  funcs.push(() => console.log(i));
}
{
  let i = 1;
  funcs.push(() => console.log(i));
}
{
  let i = 2;
  funcs.push(() => console.log(i));
}
```

## 性能影响

```javascript
// var在全局作用域中影响作用域链查找性能
var x = 1;
function test() {
  // var x = 2;  // 如果没有var，会沿着作用域链找到全局x
  // 但如果有var，会在当前作用域创建新变量，更快
}

// let/const在块级作用域中可能比var稍慢（需要管理块级作用域）
// 但在现代V8引擎中差异可以忽略

// const的语义优化
const VALUE = 100;
// 引擎知道VALUE不会被改变，可以做出优化
// 而var/let声明的变量引擎不能确定
```

# ✅严格模式有哪些限制？

# 典型回答

**严格模式（Strict Mode）** 是ES5引入的一种更严格的JavaScript执行模式，通过消除语言中一些不合理、不严谨的方面，提高代码安全性和性能。

**开启方式：**
```javascript
// 全局严格模式
'use strict';

// 函数级严格模式
function strictFunction() {
  'use strict';
  // 函数内部严格模式
}

// ES Module 和 Class 默认开启严格模式
// 不需要显式声明
```

**严格模式的主要限制：**

| 类别 | 限制 | 说明 |
|------|------|------|
| 变量 | 不允许未声明的变量赋值 | `x = 1` 抛出ReferenceError |
| 变量 | 不允许删除变量 | `delete x` 抛出SyntaxError |
| 变量 | 不允许重复参数名 | `function(a, a) {}` 报错 |
| 对象 | 不允许删除不可配置属性 | `delete Object.prototype` 报错 |
| 对象 | 不允许给只读属性赋值 | `NaN = 1` 报错 |
| this | this为undefined而不是全局对象 | 函数独立调用时 |
| 函数 | 不允许arguments.callee | 抛出TypeError |
| 函数 | arguments不追踪参数变化 | 参数与arguments无关联 |
| 函数 | eval有独立作用域 | eval内声明的变量不污染外部 |
| 语言 | 不允许with语句 | 抛出SyntaxError |
| 语言 | 不允许八进制字面量 | `0123` 报错 |
| 安全 | 不允许使用implements等保留字 | 保留字不能用作标识符 |

# 扩展知识

## 变量相关限制

```javascript
'use strict';

// 1. 未声明变量赋值报错
// x = 10; // ReferenceError: x is not defined
let x = 10; // 正确

// 2. 删除变量报错
let y = 20;
// delete y; // SyntaxError: Delete of an unqualified identifier

// 3. 重复参数名报错
// function sum(a, a, c) { // SyntaxError: Duplicate parameter name not allowed
//   return a + a + c;
// }

// 4. 使用未来的保留字
// let implements; // SyntaxError: Unexpected strict mode reserved word
// let interface;
// let package;
// let private;
// let protected;
// let public;
// let static;
// let yield;
```

## this 的严格模式行为

```javascript
'use strict';

// 1. 独立函数调用中的this为undefined
function showThis() {
  console.log(this); // undefined
}
showThis();

// 2. 全局作用域的this
console.log(this); // window（模块中为undefined）

// 3. setTimeout中的this
setTimeout(function() {
  console.log(this); // undefined（而非window）
}, 100);

// 4. 事件处理中的this
button.addEventListener('click', function() {
  console.log(this); // 仍然是触发事件的元素
});

// 5. call/apply中的基本类型不会被包装
function showType() {
  console.log(typeof this);
}
showType.call(42);      // 'number'（非严格模式是'object', Number对象）
showType.call('hello'); // 'string'
showType.call(true);    // 'boolean'

// 6. null/undefined作为thisArg
function strictNull() {
  'use strict';
  console.log(this); // null
}
strictNull.call(null); // null（非严格模式是window）
```

## arguments 对象的限制

```javascript
'use strict';

// 1. arguments与参数不再互相影响
function strictArgs(a, b) {
  a = 100;
  console.log(arguments[0]); // 1 — 不随a变化
  console.log(a);            // 100
}
strictArgs(1, 2);

// 非严格模式对比
function nonStrictArgs(a, b) {
  a = 100;
  console.log(arguments[0]); // 100 — 随a变化
}
nonStrictArgs(1, 2);

// 2. arguments.callee和arguments.caller报错
function strictCallee() {
  // arguments.callee(); // TypeError: 'caller', 'callee' access is restricted
}

// 3. 不能删除arguments
// delete arguments; // SyntaxError
```

## eval 的严格模式限制

```javascript
'use strict';

// eval在严格模式中创建独立作用域
function strictEval() {
  eval('var localVar = 10; let localLet = 20;');
  // console.log(localVar); // ReferenceError（不污染外部）
  // console.log(localLet); // ReferenceError（不污染外部）
}

// 非严格模式对比
function nonStrictEval() {
  eval('var localVar = 10;');
  console.log(localVar); // 10 — 污染了外部作用域
}

// eval本身在严格模式代码中也被视为严格模式
function callEval() {
  'use strict';
  eval('var x = 1; with({}) {}'); // with在严格模式eval中也报错
}
```

## 删除操作的限制

```javascript
'use strict';

// 1. 不能删除普通变量
let a = 1;
// delete a; // SyntaxError

// 2. 不能删除函数
function fn() {}
// delete fn; // SyntaxError

// 3. 不能删除不可配置的属性
// delete Object.prototype; // TypeError
// delete Array.prototype; // TypeError

// 4. 可以删除对象属性（如果configurable为true）
const obj = {};
Object.defineProperty(obj, 'prop', {
  value: 1,
  configurable: false
});
// delete obj.prop; // TypeError（不可配置）
```

## 对象字面量的限制

```javascript
'use strict';

// 1. 不能有重复的属性名（ES5规范）
// const obj = { x: 1, x: 2 }; // ES5中SyntaxError
// ES6中允许覆盖，不报错

// 2. 给只读属性赋值报错
const obj = {};
Object.defineProperty(obj, 'readOnly', {
  value: 42,
  writable: false
});
// obj.readOnly = 100; // TypeError: Cannot assign to read only property

// 3. 给不可扩展对象添加属性报错
const fixed = Object.preventExtensions({});
// fixed.newProp = 1; // TypeError: Cannot add property
```

## 八进制字面量的限制

```javascript
'use strict';

// 八进制字面量
// var x = 0123; // SyntaxError: Octal literals are not allowed

// ES6中可以用0o前缀
const x = 0o123; // 83（十进制）
console.log(x); // 83

// 八进制转义字符在字符串中也不允许
// var str = '\123'; // SyntaxError: Octal escape sequences are not allowed
```

## 其他限制

```javascript
'use strict';

// 1. with语句禁止
// with (Math) {
//   console.log(PI); // SyntaxError
// }

// 2. 禁止修改原始值的属性
// (1).prop = 'test'; // TypeError: Cannot create property
// 'hello'.prop = 'test'; // TypeError

// 3. 更严格的变量检查
// eval 和 arguments 不能用作标识符
// let eval = 1; // SyntaxError
// let arguments = 2; // SyntaxError

// 4. 函数声明必须在顶层或函数体
if (true) {
  // function inner() {} // ES6中允许但行为不同
}

// 5. 变量不能未声明
// 好处：提前发现bug
```

## 严格模式的好处

| 好处 | 说明 |
|------|------|
| 错误及时暴露 | 将静默失败转为显式异常 |
| 提高安全性 | 禁止eval修改作用域、禁止with |
| 性能优化 | 引擎可以做出更多优化假设 |
| 便于调试 | 避免意外全局变量等难以追踪的问题 |
| 为ES未来版本准备 | 限制了一些不规范的语法特性 |

## 默认使用严格模式的场景

```javascript
// 1. ES Module — 默认严格模式
// module.js
export function test() {
  // 这里已经是严格模式
  console.log(this); // undefined
}

// 2. Class — 默认严格模式
class MyClass {
  constructor() {
    // 严格模式
  }
  method() {
    // 严格模式
    console.log(this); // undefined（如果独立调用）
  }
}

// 3. 使用class语法定义的类的方法
```

## 最佳实践

- 新代码始终使用严格模式
- ES Module和class中不需要显式声明（默认严格模式）
- 在脚本文件开头添加 `'use strict'`
- 使用打包工具时通常会自动添加严格模式
- TypeScript编译后默认使用严格模式

# ✅事件循环机制详解：宏任务和微任务

# 典型回答

**事件循环（Event Loop）** 是JavaScript的异步执行机制，允许JavaScript在单线程环境下处理异步操作。

JavaScript是**单线程**的，但通过事件循环实现了**非阻塞I/O**。事件循环的核心是**宏任务（MacroTask）** 和**微任务（MicroTask）** 的队列管理。

**执行顺序：**

1. 执行当前宏任务（从Script代码开始）
2. 执行所有微任务（清空微任务队列）
3. 执行下一个宏任务
4. 重复步骤2-3

```
宏任务 → 微任务队列 → 宏任务 → 微任务队列 → ...
```

**常见的任务类型：**

| 任务类型 | 举例 |
|---------|------|
| 宏任务（MacroTask） | script整体代码、setTimeout、setInterval、setImmediate(Node)、I/O、UI渲染 |
| 微任务（MicroTask） | Promise.then/catch/finally、MutationObserver、process.nextTick(Node) |

# 扩展知识

## 基本执行流程

```javascript
console.log('1: script start');

setTimeout(function() {
  console.log('2: setTimeout');
}, 0);

Promise.resolve()
  .then(function() {
    console.log('3: promise1');
  })
  .then(function() {
    console.log('4: promise2');
  });

console.log('5: script end');

// 执行顺序：
// 1: script start
// 5: script end
// 3: promise1
// 4: promise2
// 2: setTimeout

// 流程分析：
// 1. 执行宏任务（script整体代码）
//    - 输出 '1: script start'
//    - setTimeout注册，放入宏任务队列
//    - Promise.then注册，放入微任务队列
//    - 输出 '5: script end'
// 2. 清空微任务队列
//    - 执行第一个then，输出 '3: promise1'
//    - 返回新Promise，第二个then注册到微任务队列
//    - 执行第二个then，输出 '4: promise2'
// 3. 取下一个宏任务
//    - 执行setTimeout回调，输出 '2: setTimeout'
```

## 完整的事件循环图示

```javascript
// 更复杂的例子
console.log('1');

setTimeout(() => {
  console.log('2');
  Promise.resolve().then(() => {
    console.log('3');
  });
}, 0);

new Promise((resolve) => {
  console.log('4');
  resolve();
}).then(() => {
  console.log('5');
});

setTimeout(() => {
  console.log('6');
}, 0);

console.log('7');

// 输出顺序：
// 1, 4, 7, 5, 2, 3, 6

// 分析：
// 宏任务1（script）: 1, 4, 7 → 清空微任务: 5
// 宏任务2（setTimeout1）: 2 → 清空微任务: 3
// 宏任务3（setTimeout2）: 6
```

## async/await与事件循环

```javascript
// async/await本质是Promise的语法糖
async function async1() {
  console.log('async1 start');
  await async2();
  console.log('async1 end');
}

async function async2() {
  console.log('async2');
}

console.log('script start');

setTimeout(() => {
  console.log('setTimeout');
}, 0);

async1();

new Promise(resolve => {
  console.log('promise1');
  resolve();
}).then(() => {
  console.log('promise2');
});

console.log('script end');

// 输出顺序：
// script start
// async1 start
// async2
// promise1
// script end
// async1 end
// promise2
// setTimeout

// 关键点：await后面的代码相当于.then中的回调
```

## process.nextTick（Node.js特有）

```javascript
// Node.js中，process.nextTick的优先级高于Promise（属于微任务）
// 但实际上nextTick有自己的队列，在微任务之前执行

process.nextTick(() => {
  console.log('nextTick1');
});

Promise.resolve().then(() => {
  console.log('promise1');
});

process.nextTick(() => {
  console.log('nextTick2');
});

// Node.js输出：
// nextTick1
// nextTick2
// promise1

// nextTick队列优先于Promise微任务队列
```

## requestAnimationFrame的位置

```javascript
// requestAnimationFrame 既不是宏任务也不是微任务
// 它在浏览器渲染之前执行
// 执行顺序：...宏任务 → 微任务 → requestAnimationFrame → 渲染 → ...

button.addEventListener('click', () => {
  Promise.resolve().then(() => console.log('microtask'));
  requestAnimationFrame(() => console.log('rAF'));
  setTimeout(() => console.log('task'));
});

// 点击后输出：
// microtask
// rAF
// task
```

## 事件循环与浏览器渲染

```javascript
// 浏览器渲染时机：在一次事件循环中，当微任务队列清空后，渲染前

document.body.style.background = 'red';
document.body.style.background = 'blue';

// 上面两行代码不会渲染两次，因为渲染发生在事件循环的末尾
// 最终只会渲染蓝色

// Promise.resolve().then(() => {
//   document.body.style.background = 'green';
// });
// 微任务中的样式变化会在同一帧中渲染
```

## Node.js 的事件循环阶段

```
   ┌───────────────────────────┐
┌─>│           timers           │ ← setTimeout/setInterval 回调
│  └─────────────┬─────────────┘
│  ┌─────────────┴─────────────┐
│  │     pending callbacks     │ ← I/O回调延迟到下一轮
│  └─────────────┬─────────────┘
│  ┌─────────────┴─────────────┐
│  │       idle, prepare       │ ← 内部使用
│  └─────────────┬─────────────┘
│  ┌─────────────┴─────────────┐
│  │           poll            │ ← 轮询I/O事件
│  └─────────────┬─────────────┘
│  ┌─────────────┴─────────────┐
│  │           check           │ ← setImmediate 回调
│  └─────────────┬─────────────┘
│  ┌─────────────┴─────────────┐
│  │      close callbacks      │ ← 关闭事件
│  └───────────────────────────┘
```

## 常见面试题

```javascript
// 面试题1
Promise.resolve().then(() => {
  console.log(1);
  Promise.resolve().then(() => {
    console.log(2);
  });
});
Promise.resolve().then(() => {
  console.log(3);
});
// 输出：1, 3, 2

// 面试题2
setTimeout(() => {
  console.log(1);
}, 0);

new Promise(resolve => {
  console.log(2);
  resolve();
  console.log(3);
}).then(() => {
  console.log(4);
});

console.log(5);

// 输出：2, 3, 5, 4, 1

// 面试题3
setTimeout(() => {
  console.log('timeout1');
  Promise.resolve().then(() => console.log('promise1'));
}, 0);

setTimeout(() => {
  console.log('timeout2');
  Promise.resolve().then(() => console.log('promise2'));
}, 0);

// 输出：timeout1, promise1, timeout2, promise2
// 每个宏任务前都会清空微任务队列
```

## 宏任务与微任务的关系

```javascript
// 微任务可以"插队" — 在宏任务之间执行
setTimeout(() => console.log('task1'), 0);

Promise.resolve().then(() => {
  console.log('micro1');
  Promise.resolve().then(() => {
    console.log('micro2');
    Promise.resolve().then(() => {
      console.log('micro3');
    });
  });
});

setTimeout(() => console.log('task2'), 0);

// 输出：
// micro1, micro2, micro3, task1, task2

// 注意：微任务队列是在每个宏任务完成后清空
// 微任务中产生的新微任务也会在同一个周期被执行

// 如果微任务无限产生新微任务，会阻塞宏任务执行
Promise.resolve().then(function microTask() {
  console.log('micro');
  Promise.resolve().then(microTask); // 产生新微任务
});
setTimeout(() => console.log('task'), 0);
// 'micro' 会无限输出，task永远无法执行（主线程饥饿）
```

# ✅什么是BigInt？解决了什么问题？

# 典型回答

**BigInt**是ES2020引入的JavaScript第七种原始数据类型，用于表示**任意精度**的整数。它解决了JavaScript中Number类型无法精确表示大整数的问题。

**Number类型的安全限制：**
- JavaScript的Number采用IEEE 754双精度64位浮点数
- 安全整数范围：`-(2^53 - 1)` 到 `2^53 - 1`（约9千万亿）
- 超过此范围的计算会**丢失精度**

```javascript
// Number类型的大整数问题
console.log(9007199254740991 + 1); // 9007199254740992 ✓
console.log(9007199254740991 + 2); // 9007199254740992 ✗ 精度丢失
console.log(9999999999999999);     // 10000000000000000 精度丢失
```

**BigInt的创建方式：**
```javascript
// 方式一：在整数末尾加n
const big1 = 9007199254740991n;

// 方式二：BigInt() 函数
const big2 = BigInt(9007199254740991);
const big3 = BigInt('9007199254740991');

console.log(typeof big1); // 'bigint'
```

# 扩展知识

## BigInt的基本运算

```javascript
const a = 1000000000000000000n;
const b = 2000000000000000000n;

// 基本算术运算
console.log(a + b);  // 3000000000000000000n
console.log(b - a);  // 1000000000000000000n
console.log(a * 2n); // 2000000000000000000n
console.log(b / 3n); // 666666666666666666n（除法会截断小数）
console.log(a % 3n); // 1n
console.log(a ** 2n); // 1000000000000000000000000000000000000n

// 位运算
console.log(a & b);  // 支持 & | ^ ~ << >> 等位运算
console.log(a | b);
console.log(a ^ b);
```

## BigInt与Number的混用限制

**BigInt不能直接与Number混合运算：**
```javascript
const big = 1n;
const num = 1;

// console.log(big + num);  // TypeError: Cannot mix BigInt and other types
// console.log(big > num);  // TypeError

// 必须显式转换
console.log(big + BigInt(num));   // 2n
console.log(Number(big) + num);   // 2
```

**比较运算符例外：**
```javascript
// 比较运算符可以混用（因为比较的是值而非类型）
console.log(1n == 1);   // true （宽松相等）
console.log(1n === 1);  // false （严格相等，类型不同）
console.log(1n < 2);    // true
console.log(2n > 1);    // true
```

## BigInt与Math对象

```javascript
const big = 16n;

// Math对象的方法不支持BigInt
// console.log(Math.sqrt(big));  // TypeError

// 需要手动转换
console.log(Math.sqrt(Number(big)));  // 4
```

## BigInt的JSON序列化

```javascript
const obj = { value: 9007199254740991n };

// 直接JSON.stringify会报错
// JSON.stringify(obj);  // TypeError: Do not know how to serialize a BigInt

// 需要自定义序列化
const json = JSON.stringify(obj, (key, value) =>
  typeof value === 'bigint' ? value.toString() : value
);
console.log(json); // {"value":"9007199254740991"}

// 或者使用toJSON方法
BigInt.prototype.toJSON = function() {
  return this.toString();
};
console.log(JSON.stringify(obj)); // {"value":"9007199254740991"}
```

## 应用场景

```javascript
// 1. 高精度金融计算
const price = 12345678901234567890n;
const quantity = 1000000n;
const total = price * quantity;
// 精确的大数乘法结果

// 2. 数据库ID处理
// 数据库生成的BigInt ID（如Snowflake ID）
const userId = BigInt('1623456789012345678');
console.log(userId.toString()); // 数据库查询使用

// 3. 加密算法中的大数运算
const modulus = 2n ** 256n - 2n ** 224n + 2n ** 192n + 2n ** 96n - 1n;
// 用于椭圆曲线加密的质数

// 4. 时间戳精确计算
const start = BigInt(Date.now()) * 1000000n;
// 纳秒级时间戳

// 5. 科学计算
const avogadro = 602214076000000000000000n; // 阿伏伽德罗常数
```

## BigInt的性能注意事项

```javascript
// BigInt运算比Number慢得多（可能慢2-10倍）
console.time('BigInt');
let sum = 0n;
for (let i = 0n; i < 100000n; i++) sum += i;
console.timeEnd('BigInt');

console.time('Number');
let sum2 = 0;
for (let i = 0; i < 100000; i++) sum2 += i;
console.timeEnd('Number');

// 不需要大整数时不要使用BigInt
```

## BigInt的局限性

```javascript
// 1. 不能用于单精度运算（如Math、浮点数）
// Math.round(1n); // TypeError

// 2. 不能混合运算
// 1n + 1; // TypeError

// 3. 不能用于JSON.stringify（默认）
// 4. 除法的截断行为
console.log(5n / 2n); // 2n（向零取整）

// 5. 不支持一元正号
// +1n; // TypeError
// 但支持负号
console.log(-1n); // -1n

// 6. 不能用于类型转换暗示为数字
console.log(String(1n)); // '1' ✔
console.log(Boolean(1n)); // true ✔ （只有0n是false）
// Number(1n); // 可能丢失精度但可以执行
console.log(Number(1n)); // 1

// 7. 无符号右移（>>>）不支持
// 1n >>> 0n; // TypeError: BigInts have no unsigned right shift
```

## BigInt与TypeScript

```typescript
// TypeScript中BigInt的类型是 bigint
let big: bigint = 100n;

// 需要target为ES2020+
// tsconfig.json: "target": "ES2020"
```

## 何时使用BigInt

- 需要精确表示大于2^53-1的整数
- 金融计算（金额的精确整数表示）
- 加密和哈希算法
- 数据库中的64位或128位ID
- 科学计算中的大整数

**不需要使用BigInt的场景：**
- 小整数常规计算
- 涉及小数的计算（BigInt不支持小数）
- 性能敏感但有精度容忍的场景
- 需要频繁与JSON交互的场景

# ✅什么是内存泄漏？常见的内存泄漏场景和排查方法

# 典型回答

**内存泄漏（Memory Leak）** 是指程序申请的内存使用完后没有被正确释放，导致这部分内存无法被再次使用。随着时间推移，内存泄漏会导致可用内存越来越少，最终引发性能下降甚至程序崩溃。

**内存泄漏对应用的影响：**
- 页面响应越来越慢
- 浏览器占用内存持续增长
- 频繁触发垃圾回收导致卡顿
- 最终可能导致"Out of Memory"崩溃

**常见的内存泄漏场景：**

| 场景 | 原因 | 示例 |
|------|------|------|
| 意外的全局变量 | 未声明的变量或全局缓存 | `function() { leaked = 'value'; }` |
| 被遗忘的定时器 | setInterval未清除 | 定时器引用的对象无法释放 |
| 闭包 | 闭包长期持有外部变量 | React Hooks中的闭包陷阱 |
| DOM引用 | 移除DOM但JS仍持有引用 | `const el = document.getElementById('id')` |
| 事件监听器 | 未移除的事件监听 | addEventListener未remove |
| 脱离DOM的引用 | 从DOM树移除但未被GC | 变量中保存了DOM元素引用 |
| Map/Set中的键 | 对象键不被释放 | 使用WeakMap替代 |
| 大对象缓存 | 无限增长的缓存 | 缓存没有大小限制 |

# 扩展知识

## 意外的全局变量

```javascript
// 场景1：未声明的变量
function createLeak() {
  leaked = '全局变量'; // 严格模式会报错
  this.anotherLeak = '也泄露'; // this指向全局
}

// 场景2：全局数组无限增长
const cache = [];
function addToCache(item) {
  cache.push(item); // 不断增长，没有上限
}

// 解决方案
'use strict'; // 防止意外全局变量

// 限制缓存大小
class LimitedCache {
  constructor(maxSize = 100) {
    this.maxSize = maxSize;
    this.cache = new Map();
  }
  set(key, value) {
    if (this.cache.size >= this.maxSize) {
      const firstKey = this.cache.keys().next().value;
      this.cache.delete(firstKey);
    }
    this.cache.set(key, value);
  }
}
```

## 被遗忘的定时器

```javascript
// 内存泄漏示例
function startTimer() {
  const data = new Array(1000000).fill('heavy data');
  const timerId = setInterval(() => {
    console.log(data.length); // data一直被引用
  }, 1000);
  // 没有返回timerId，外部无法清除
}

// 正确写法
function startTimerSafe() {
  const data = new Array(1000000).fill('heavy data');
  const timerId = setInterval(() => {
    console.log(data.length);
  }, 1000);

  // 返回清除函数
  return () => clearInterval(timerId);
}

const stopTimer = startTimerSafe();
// 不再需要时
stopTimer();

// 请求动画帧同理
let animationId;
function startAnimation() {
  function animate() {
    // ...
    animationId = requestAnimationFrame(animate);
  }
  animate();
}
// 需要取消
// cancelAnimationFrame(animationId);
```

## DOM引用泄漏

```javascript
// 场景：保存DOM引用，但DOM被移除后仍被引用
class Dialog {
  constructor() {
    this.element = document.createElement('div');
    document.body.appendChild(this.element);
  }

  destroy() {
    document.body.removeChild(this.element);
    // this.element仍然引用着已移除的DOM
    // 如果Dialog实例长期存在，DOM不会被GC回收
  }

  // 正确做法
  destroyProperly() {
    document.body.removeChild(this.element);
    this.element = null; // 释放引用
  }
}

// 场景2：DOM元素引用在数组中
const elements = [];
function trackElement(el) {
  elements.push(el);
  // 即使DOM被移除，数组中的引用阻止GC

  // 更安全的做法：使用WeakRef
  const ref = new WeakRef(el);
}
```

## 事件监听器泄漏

```javascript
// 未移除的事件监听器
class Button {
  constructor(element) {
    this.element = element;
    this.handleClick = () => {
      console.log('clicked', this);
    };
    element.addEventListener('click', this.handleClick);
    // 没有removeEventListener
  }

  destroy() {
    this.element.removeEventListener('click', this.handleClick);
    this.element = null;
  }
}

// 被动引用问题
document.addEventListener('scroll', () => {
  // 匿名函数无法移除
});

// 正确的做法：使用具名函数或AbortController
const controller = new AbortController();
document.addEventListener('scroll', handler, { signal: controller.signal });
// 移除
controller.abort();
```

## React中的内存泄漏

```javascript
// React组件中的常见内存泄漏

// 场景1：组件卸载后setState
function UserProfile({ userId }) {
  const [user, setUser] = useState(null);

  useEffect(() => {
    fetchUser(userId).then(data => {
      // 如果组件在请求完成前卸载，setState会导致泄漏
      setUser(data);
    });
  }, [userId]);

  // 修复：
  useEffect(() => {
    let cancelled = false;
    fetchUser(userId).then(data => {
      if (!cancelled) setUser(data);
    });
    return () => { cancelled = true; };
  }, [userId]);
}

// 场景2：事件监听未清理
function Chat() {
  useEffect(() => {
    socket.on('message', handleMessage);
    return () => {
      socket.off('message', handleMessage); // 清理
    };
  }, []);
}

// 场景3：定时器未清理
function Timer() {
  const [count, setCount] = useState(0);

  useEffect(() => {
    const id = setInterval(() => {
      setCount(c => c + 1);
    }, 1000);
    return () => clearInterval(id);
  }, []);
}
```

