## 传统回调地狱中的并行操作

```javascript
// 回调地狱中的并行操作（更复杂）
let results = {};
let completed = 0;

function checkDone() {
  completed++;
  if (completed === 3) {
    // 所有操作完成
    processResults(results);
  }
}

