## Promise.all的局限性

```javascript
// 1. 即使一个Promise失败，其他Promise仍然会执行
Promise.all([
  new Promise(resolve => setTimeout(() => {
    console.log('仍然执行');
    resolve('A');
  }, 100)),
  Promise.reject(new Error('快速失败'))
]).catch(() => {}); // 输出 '仍然执行'

// 2. 不能优雅处理部分失败
// 如果需要部分失败，使用allSettled

// 3. 大并发量的限制
async function processBatch(items, batchSize = 10) {
  const results = [];
  for (let i = 0; i < items.length; i += batchSize) {
    const batch = items.slice(i, i + batchSize);
    const batchResults = await Promise.all(
      batch.map(item => processItem(item))
    );
    results.push(...batchResults);
  }
  return results;
}
```

## 现代替代方案

```javascript
// 在现代JavaScript中：
// 使用原生 Promise.all
const results = await Promise.all(promises);

// 需要部分失败时使用 allSettled
const settled = await Promise.allSettled(promises);

// 需要自定义并发控制
async function concurrentMap(items, maxConcurrency, fn) {
  const results = [];
  let index = 0;

  async function worker() {
    while (index < items.length) {
      const currentIndex = index++;
      results[currentIndex] = await fn(items[currentIndex], currentIndex);
    }
  }

  const workers = Array.from({ length: maxConcurrency }, worker);
  await Promise.all(workers);
  return results;
}
```

# ✅如何实现对象的深拷贝？有哪些方案和缺陷？

# 典型回答

深拷贝（Deep Copy）是指创建一个新对象，递归复制原对象所有层级的数据，新对象与原对象**完全独立**，互不影响。与之相对，浅拷贝（Shallow Copy）只复制第一层属性，嵌套对象仍共享引用。

**常见深拷贝方案：**

| 方案 | 适用场景 | 缺陷 |
|------|---------|------|
| JSON.parse(JSON.stringify(obj)) | 简单对象，无特殊类型 | 无法处理函数、undefined、Symbol、循环引用、Date、RegExp等 |
| 递归手写深拷贝 | 需要自定义控制 | 需要自行处理各种边界情况 |
| structuredClone() | 现代浏览器/Node 17+ | 不支持函数和Symbol |
| lodash.cloneDeep() | 生产环境 | 需要引入第三方库 |
| MessageChannel | 部分特殊场景 | 异步、不支持函数 |

# 扩展知识

## JSON.parse/stringify 方案的缺陷

```javascript
const obj = {
  name: 'Alice',
  age: undefined,        // 丢失
  sayHi: function() {},  // 丢失
  sym: Symbol('key'),    // 丢失
  date: new Date(),      // 变成字符串
  reg: /test/i,          // 变成空对象{}
  map: new Map(),        // 变成空对象{}
  set: new Set(),        // 变成空对象{}
  nan: NaN,              // 变成 null
  inf: Infinity,         // 变成 null
  negInf: -Infinity,     // 变成 null
};

const cloned = JSON.parse(JSON.stringify(obj));
console.log(cloned);
// { name: 'Alice', date: '2024-...', reg: {}, map: {}, set: {}, nan: null, ... }

// 循环引用会抛出错误
const circular = { self: null };
circular.self = circular;
// JSON.stringify(circular); // TypeError: Converting circular structure to JSON
```

## 手动实现深拷贝

```javascript
function deepClone(value, map = new WeakMap()) {
  // 处理基本类型
  if (value === null || typeof value !== 'object') return value;

  // 处理循环引用
  if (map.has(value)) return map.get(value);

  // 处理特殊对象类型
  if (value instanceof Date) return new Date(value);
  if (value instanceof RegExp) return new RegExp(value.source, value.flags);
  if (value instanceof Map) {
    const cloned = new Map();
    map.set(value, cloned);
    value.forEach((v, k) => cloned.set(deepClone(k, map), deepClone(v, map)));
    return cloned;
  }
  if (value instanceof Set) {
    const cloned = new Set();
    map.set(value, cloned);
    value.forEach(v => cloned.add(deepClone(v, map)));
    return cloned;
  }
  if (value instanceof WeakMap || value instanceof WeakSet) return value;
  if (ArrayBuffer.isView(value)) return value.slice(0);
  if (value instanceof Promise) return value; // Promise不可转移

  // 处理普通对象和数组
  const cloned = Array.isArray(value) ? [] : {};
  map.set(value, cloned);

  // 复制所有属性（包括Symbol属性）
  for (const key of [...Object.keys(value), ...Object.getOwnPropertySymbols(value)]) {
    cloned[key] = deepClone(value[key], map);
  }

  return cloned;
}

// 测试
const obj = {
  num: 1,
  str: 'hello',
  bool: true,
  null: null,
  undefined: undefined,
  arr: [1, { a: 2 }],
  obj: { x: 1, y: { z: 2 } },
  date: new Date('2024-01-01'),
  regex: /test/gi,
  map: new Map([['key', 'value']]),
  set: new Set([1, 2, 3]),
  [Symbol('sym')]: 'symbol value',
  nested: { deep: { deeper: { value: 42 } } }
};

const cloned = deepClone(obj);
console.log(cloned.date instanceof Date); // true
console.log(cloned.regex instanceof RegExp); // true
console.log(cloned.arr !== obj.arr); // true
console.log(cloned.nested.deep.deeper !== obj.nested.deep.deeper); // true
```

## structuredClone() 方案

```javascript
// Node 17+ / 现代浏览器内置
const obj = {
  name: 'Alice',
  scores: [95, 88, 92],
  address: { city: 'Beijing' },
  date: new Date(),
  reg: /test/i,
  map: new Map([['key', 'value']]),
  set: new Set([1, 2, 3]),
  blob: new Blob(['hello']),
};

const cloned = structuredClone(obj);
console.log(cloned.date instanceof Date);      // true
console.log(cloned.reg instanceof RegExp);      // true
console.log(cloned.map instanceof Map);         // true
console.log(cloned.set instanceof Set);         // true

// 仍然不支持
// const obj2 = { fn: () => {}, sym: Symbol() };
// structuredClone(obj2); // DataCloneError
```

## lodash.cloneDeep

```javascript
// 生产环境最完善的方案
import _ from 'lodash';

const obj = { /* 任意复杂对象 */ };
const cloned = _.cloneDeep(obj);

// lodash的实现会处理：
// - 所有基本类型
// - 数组和对象
// - Date、RegExp、Map、Set、Buffer
// - 循环引用
// - 原型链
// - 各种边界情况
```

## MessageChannel 方案

```javascript
// 利用结构化克隆算法（异步）
function structuralClone(obj) {
  return new Promise(resolve => {
    const { port1, port2 } = new MessageChannel();
    port2.onmessage = ev => resolve(ev.data);
    port1.postMessage(obj);
  });
}

// 使用
const obj = { /* ... */ };
structuralClone(obj).then(cloned => {
  console.log(cloned);
});
```

## 各方案对比表

| 特性 | JSON | 手写递归 | structuredClone | lodash.cloneDeep |
|------|:----:|:--------:|:---------------:|:----------------:|
| 基本类型 | ✓ | ✓ | ✓ | ✓ |
| 嵌套对象 | ✓ | ✓ | ✓ | ✓ |
| 数组 | ✓ | ✓ | ✓ | ✓ |
| 函数 | ✗ | 可处理 | ✗ | ✓ |
| undefined | ✗ | ✓ | ✓ | ✓ |
| Symbol属性 | ✗ | ✓ | ✗ | ✓ |
| Date | ✗(字符串) | ✓ | ✓ | ✓ |
| RegExp | ✗(空对象) | ✓ | ✓ | ✓ |
| Map | ✗(空对象) | ✓ | ✓ | ✓ |
| Set | ✗(空对象) | ✓ | ✓ | ✓ |
| 循环引用 | ✗(报错) | ✓ | ✓ | ✓ |
| 原型链 | 丢失 | 可保留 | 丢失 | 可保留 |
| BigInt | ✗ | ✓ | ✓ | ✓ |
| ArrayBuffer | ✗ | ✓(slice) | ✓ | 部分支持 |
| 同步/异步 | 同步 | 同步 | 同步 | 同步 |
| 性能 | 快 | 中等 | 最快 | 中 |

## 浅拷贝回顾

```javascript
// 浅拷贝方式
const obj = { a: 1, nested: { b: 2 } };

// 1. 扩展运算符
const spread = { ...obj };

// 2. Object.assign
const assigned = Object.assign({}, obj);

// 3. 数组的slice/concat/from
const arr = [1, { a: 2 }];
const sliced = arr.slice();
const concated = arr.concat();
const fromArr = Array.from(arr);

// 浅拷贝的陷阱
spread.nested.b = 99;
console.log(obj.nested.b); // 99 — 互相影响！
```

## 深拷贝的性能考量

```javascript
// 对于大型对象，深拷贝很耗时
const largeObj = {};
for (let i = 0; i < 100000; i++) {
  largeObj[`key_${i}`] = { value: i, nested: { data: `string_${i}` } };
}

console.time('JSON');
const jsonClone = JSON.parse(JSON.stringify(largeObj));
console.timeEnd('JSON');

console.time('structuredClone');
const scClone = structuredClone(largeObj);
console.timeEnd('structuredClone');

// structuredClone 通常比 JSON 快 2-5 倍
```

## 选择指南

- **日常简单对象**：`JSON.parse(JSON.stringify(obj))`（确认无特殊类型）
- **现代环境（Node 17+/Chrome 98+）**：`structuredClone()`
- **生产级完整方案**：`lodash.cloneDeep()`
- **需要深度控制**：手写深拷贝函数
- **性能优先**：`structuredClone()` 或 MessageChannel

# ✅宏任务和微任务有哪些？执行顺序是怎样的？

# 典型回答

## 宏任务（MacroTask）和微任务（MicroTask）列表

**宏任务（MacroTask）：**

| 来源 | 具体API |
|------|---------|
| 主代码块 | script整体代码 |
| 定时器 | setTimeout、setInterval |
| I/O | DOM事件、网络请求回调、文件操作 |
| 浏览器专用 | requestAnimationFrame（介于宏任务和渲染之间） |
| Node.js 专用 | setImmediate、I/O回调 |

**微任务（MicroTask）：**

| 来源 | 具体API |
|------|---------|
| Promise | Promise.then/catch/finally |
| MutationObserver | DOM变化观察 |
| queueMicrotask | 显式创建微任务 |
| Node.js 专用 | process.nextTick |

## 执行顺序规则

```
1. 执行一个宏任务（从script开始）
2. 执行所有微任务（清空微任务队列）
3. 执行下一个宏任务
4. 重复步骤2-3

在一次循环中：一个宏任务 → 所有微任务 → 可能渲染 → 下一个宏任务
```

**核心原则：**
- 每个宏任务执行完后，都会清空微任务队列
- 微任务中产生的新微任务会继续在当前循环中执行
- 微任务队列总是在下一个宏任务之前被清空

# 扩展知识

## 基本示例

```javascript
console.log('1: script start');

setTimeout(() => {
  console.log('2: setTimeout');
}, 0);

Promise.resolve().then(() => {
  console.log('3: promise1');
});

Promise.resolve().then(() => {
  console.log('4: promise2');
});

console.log('5: script end');

// 输出顺序：
// 1: script start
// 5: script end
// 3: promise1
// 4: promise2
// 2: setTimeout
```

## 微任务递归的情况

```javascript
// 微任务中创建微任务——会继续在当前循环中执行
Promise.resolve().then(() => {
  console.log('micro 1');
  Promise.resolve().then(() => {
    console.log('micro 2');
    Promise.resolve().then(() => {
      console.log('micro 3');
    });
  });
});

setTimeout(() => {
  console.log('task 1');
}, 0);

// 输出：
// micro 1
// micro 2
// micro 3
// task 1

// 微任务队列会在宏任务之前被完全清空
```

## 宏任务与微任务的嵌套

```javascript
setTimeout(() => {
  console.log('task1');
  Promise.resolve().then(() => {
    console.log('micro in task1');
  });
}, 0);

setTimeout(() => {
  console.log('task2');
  Promise.resolve().then(() => {
    console.log('micro in task2');
  });
}, 0);

// 输出：
// task1
// micro in task1
// task2
// micro in task2

// 每个宏任务后都会清空微任务队列
```

## 复杂综合示例

```javascript
console.log('1');

setTimeout(() => {
  console.log('2');
  Promise.resolve().then(() => console.log('3'));
}, 0);

new Promise((resolve) => {
  console.log('4');
  resolve();
}).then(() => {
  console.log('5');
  setTimeout(() => console.log('6'), 0);
  Promise.resolve().then(() => console.log('7'));
});

setTimeout(() => {
  console.log('8');
  Promise.resolve().then(() => console.log('9'));
}, 0);

console.log('10');

// 逐步分析：
// 宏任务1（script）:
//   console.log('1') → 1
//   setTimeout(2) → 宏任务队列: [2]
//   Promise执行器: console.log('4') → 4, resolve()
//   .then(5) → 微任务队列: [5]
//   setTimeout(8) → 宏任务队列: [2, 8]
//   console.log('10') → 10
//   输出: 1, 4, 10
//
// 清空微任务:
//   .then(5): console.log('5') → 5
//            setTimeout(6) → 宏任务队列: [2, 8, 6]
//            Promise.resolve().then(7) → 微任务队列: [7]
//   执行微任务7: console.log('7') → 7
//   输出: 5, 7
//
// 宏任务2（setTimeout2）:
//   console.log('2') → 2
//   Promise.resolve().then(3) → 微任务队列: [3]
//   清空微任务: console.log('3') → 3
//   输出: 2, 3
//
// 宏任务3（setTimeout8）:
//   console.log('8') → 8
//   Promise.resolve().then(9) → 微任务队列: [9]
//   清空微任务: console.log('9') → 9
//   输出: 8, 9
//
// 宏任务4（setTimeout6）:
//   console.log('6') → 6
//   输出: 6

// 最终输出: 1, 4, 10, 5, 7, 2, 3, 8, 9, 6
```

## Node.js 中的差异

```javascript
// Node.js 中 process.nextTick 优先级高于 Promise 微任务
process.nextTick(() => {
  console.log('nextTick');
});

Promise.resolve().then(() => {
  console.log('promise');
});

// Node.js 输出：nextTick → promise

// 执行顺序：nextTick队列 → 微任务队列 → 宏任务

// process.nextTick 实际上是"nextTickQueue"，比微任务更优先
// 可以创建"深度递归"
function recursiveNextTick() {
  process.nextTick(() => {
    console.log('nextTick');
    recursiveNextTick(); // 无限递归
  });
}
// 这会导致I/O任务被"饿死"
```

## queueMicrotask 的使用

```javascript
// 显式创建微任务（代替Promise.resolve().then()）
queueMicrotask(() => {
  console.log('microtask');
});

// 相当于
Promise.resolve().then(() => {
  console.log('microtask');
});

// 使用场景：需要在当前同步代码执行完毕后、渲染前执行回调
function measurePerformance() {
  queueMicrotask(() => {
    console.log('同步代码执行完毕');
    // 测量性能
  });
}
```

## requestAnimationFrame 的位置

```javascript
// requestAnimationFrame 的特殊位置
// 执行顺序：宏任务 → 微任务 → requestAnimationFrame → 渲染 → requestIdleCallback

console.log('1: start');

setTimeout(() => {
  console.log('2: setTimeout');
}, 0);

requestAnimationFrame(() => {
  console.log('3: rAF');
});

Promise.resolve().then(() => {
  console.log('4: promise');
});

console.log('5: end');

// 通常输出：
// 1, 5, 4, 3, 2
// 或者
// 1, 5, 4, 2, 3

// 注意：setTimeout和rAF的顺序在不同浏览器可能不同
// 但微任务（promise）总是在两者之前
```

## 浏览器与Node.js的事件循环对比

| 阶段 | 浏览器 | Node.js |
|------|--------|---------|
| 微任务优先级 | 每次宏任务后清空 | 每个阶段后清空 |
| process.nextTick | 不存在 | 比Promise更高优先级 |
| setImmediate | 不存在 | 在check阶段执行 |
| 渲染时机 | 微任务后、下一个宏任务前 | 无渲染概念 |
| 任务队列 | 宏任务和微任务两个队列 | 多个阶段队列 |

## 实际应用

```javascript
// 1. 在微任务中批量更新
let pendingUpdates = [];
let scheduled = false;

function scheduleUpdate(update) {
  pendingUpdates.push(update);
  if (!scheduled) {
    scheduled = true;
    queueMicrotask(() => {
      const updates = pendingUpdates;
      pendingUpdates = [];
      scheduled = false;
      // 批量处理所有更新
      updates.forEach(fn => fn());
    });
  }
}

// 2. 分割长任务
function processLargeData(items) {
  let index = 0;

  function processChunk() {
    const start = performance.now();
    while (index < items.length && performance.now() - start < 16) {
      processItem(items[index++]);
    }
    if (index < items.length) {
      // 使用宏任务让出主线程
      setTimeout(processChunk, 0);
    }
  }

  setTimeout(processChunk, 0);
}
```

## 最佳实践

- **避免在微任务中创建无限循环**（会阻塞主线程）
- **UI更新相关的操作放在宏任务中**（给渲染留机会）
- **高优先级任务用 queueMicrotask**
- **长任务分割用 setTimeout**
- 理解执行顺序有助于调试异步bug

# ✅常见this指向的面试题分析

# 典型回答

this指向是JavaScript面试中的高频考点，主要考察对**绑定规则**、**优先级**和**箭头函数**的理解。以下是最常见的this面试题类型。

**核心判断流程：**
1. 函数是箭头函数？ → this继承外层作用域
2. 是否通过new调用？ → this指向新创建的对象
3. 是否通过call/apply/bind调用？ → this指向指定的对象
4. 是否作为对象方法调用？ → this指向调用该方法的对象
5. 默认规则：严格模式→undefined，非严格模式→全局对象

