## WeakRef 和 FinalizationRegistry

```javascript
// WeakRef（ES2021）— 更直接的弱引用
class ImageCache {
  constructor() {
    this.cache = new Map();
  }

  loadImage(url) {
    let ref = this.cache.get(url);

    if (ref) {
      const cached = ref.deref();
      if (cached) {
        console.log('从缓存加载');
        return cached;
      }
      console.log('缓存已被GC回收');
    }

    const img = new Image();
    img.src = url;
    // 存储弱引用
    this.cache.set(url, new WeakRef(img));
    return img;
  }

  // 清理已回收的引用
  cleanCache() {
    for (const [url, ref] of this.cache) {
      if (!ref.deref()) {
        this.cache.delete(url);
      }
    }
  }
}

// FinalizationRegistry — 监听对象被回收
const registry = new FinalizationRegistry((heldValue) => {
  console.log(`清理资源: ${heldValue}`);
});

class Resource {
  constructor(name) {
    this.name = name;
    this.handle = allocateResource(name);

    // 注册回调：当this被回收时调用
    registry.register(this, name);
  }

  release() {
    // 手动释放
    freeResource(this.handle);
    registry.unregister(this);
  }
}

function allocateResource(name) {
  console.log(`分配资源: ${name}`);
  return Symbol(name);
}

function freeResource(handle) {
  console.log(`释放资源: ${handle.toString()}`);
}

// 使用
let res = new Resource('file-handle');
res = null; // 当GC运行时，会打印 "清理资源: file-handle"
```

## 强引用与弱引用的对比

```javascript
// 强引用行为
let strongRef = { data: 'important' };
let anotherStrongRef = strongRef; // 两个强引用

strongRef = null; // 还有 anotherStrongRef 在引用，对象不会被回收

anotherStrongRef = null; // 此时没有强引用了，对象可被GC回收

// 弱引用行为
let obj3 = { data: 'temp' };
const weakRef = new WeakRef(obj3);

console.log(weakRef.deref()?.data); // 'temp'

obj3 = null;
// 下次GC运行后，weakRef.deref() 返回 undefined

// 关键区别：弱引用不会"延长"对象的生命周期
// 如果对象只剩下弱引用，GC会立即回收它
```

## 强引用导致的内存泄漏

```javascript
// 使用Map（强引用）导致的内存泄漏
const userSettings = new Map();

function getUserSettings(user) {
  if (!userSettings.has(user)) {
    userSettings.set(user, fetchSettings(user.id));
  }
  return userSettings.get(user);
}

let user = { id: 1, name: 'Alice' };
getUserSettings(user);

user = null; // user对象被置空
// 但userSettings中仍然存在user的引用
// user对象不能被GC回收！

// 使用WeakMap解决
const userSettingsWeak = new WeakMap();
// 当user对象被置空时，WeakMap中的条目自动清理
```

## 选择指南

| 场景 | 推荐 | 原因 |
|------|------|------|
| DOM节点关联数据 | WeakMap | DOM移除时自动清理 |
| 对象缓存 | WeakMap | 缓存不会阻止对象回收 |
| 对象标记集合 | WeakSet | 不影响对象的GC |
| 私有属性存储 | WeakMap | 与实例同生命周期 |
| 常规数据存储 | Map/Set | 需要遍历和size属性 |
| 公共数据缓存 | Map | 需要控制缓存生命周期 |
| 用户会话数据 | Map | 需要手动管理会话 |
| 事件监听器存储 | WeakMap | 与DOM元素生命周期绑定 |

## 注意事项

```javascript
// 1. WeakRef的deref()结果不可预测
function useWeakRef() {
  const ref = new WeakRef({});
  const obj = ref.deref();
  // obj可能在任何时候变成undefined
  // 不能假设obj会存在
}

// 2. FinalizationRegistry的回调时机不确定
// 回调可能在主线程或GC线程执行
// 不要在回调中执行关键操作

// 3. WeakMap不可迭代
const wm = new WeakMap();
// wm.keys() // TypeError
// wm.values() // TypeError
// wm.size // undefined

// 4. 基本类型不能作为弱引用键
// wm.set(42, 'value') // TypeError: Invalid value used as weak map key

// 5. 弱引用不应该被滥用
// 大多数场景使用强引用即可
// 弱引用适用于：缓存、元数据、DOM关联等特殊场景
```

# ✅扩展运算符和剩余参数有什么区别？

# 典型回答

扩展运算符（Spread Operator）和剩余参数（Rest Parameters）都使用三个点`...`作为前缀，但它们的作用和使用场景正好相反：

**核心区别：**

| 对比维度 | 扩展运算符 (...) | 剩余参数 (...) |
|---------|----------------|---------------|
| 使用位置 | 函数调用或字面量中 | 函数参数定义中 |
| 作用 | 将可迭代对象"展开"为独立元素 | 将多个参数"收集"为数组 |
| 展开/收集 | 展开（拆散） | 收集（聚合） |
| 出现位置 | 在数组/对象字面量、函数调用中作为值 | 在函数参数列表的最后一个位置 |

**简单记忆：**
- **剩余参数**：在**函数定义**时使用，将不确定的参数收集成一个数组
- **扩展运算符**：在**函数调用**或**字面量**中使用，将数组或对象展开成单个元素

# 扩展知识

## 剩余参数详解

```javascript
// 基本用法：收集剩余参数
function sum(...numbers) {
  return numbers.reduce((total, n) => total + n, 0);
}
console.log(sum(1, 2, 3, 4)); // 10

// 与普通参数结合（剩余参数必须在最后）
function log(name, role, ...scores) {
  console.log(`${name} (${role}): ${scores.join(', ')}`);
}
log('Alice', 'Student', 95, 88, 92);
// Alice (Student): 95, 88, 92

// 代替arguments对象
function oldWay() {
  console.log(arguments.length); // 类数组，不是真正的数组
}
function newWay(...args) {
  console.log(args.length); // 真正的数组
}

// 箭头函数中的剩余参数（唯一获得可变参数的方式）
const arrowSum = (...nums) => nums.reduce((a, b) => a + b, 0);
```

## 扩展运算符详解

```javascript
// 1. 展开数组
const arr1 = [1, 2, 3];
const arr2 = [4, 5, 6];
const combined = [...arr1, ...arr2]; // [1, 2, 3, 4, 5, 6]

// 2. 复制数组（浅拷贝）
const original = [1, 2, [3, 4]];
const clone = [...original];
clone[2][0] = 99;
console.log(original[2][0]); // 99 — 浅拷贝，嵌套对象仍共享引用

// 3. 展开对象（ES2018）
const obj1 = { a: 1, b: 2 };
const obj2 = { c: 3, ...obj1 }; // { c: 3, a: 1, b: 2 }
console.log(obj2);

// 4. 合并对象（后面的属性会覆盖前面的）
const merged = { ...obj1, ...{ b: 99, d: 4 } };
console.log(merged); // { a: 1, b: 99, d: 4 }

// 5. 展开字符串
const chars = [...'hello'];
console.log(chars); // ['h', 'e', 'l', 'l', 'o']

// 6. 展开Set/Map
const set = new Set([1, 2, 3]);
const arr = [...set]; // [1, 2, 3]

// 7. 函数调用中展开
const nums = [3, 1, 4, 1, 5];
console.log(Math.max(...nums)); // 5
```

## 深入对比

```javascript
// 剩余参数 — 在函数定义时收集
function show(first, ...rest) {
  // rest 是数组 [2, 3, 4]
}
show(1, 2, 3, 4);

// 扩展运算符 — 在函数调用时展开
const args = [2, 3, 4];
show(1, ...args); // 等价于 show(1, 2, 3, 4)

// 两者配合使用
function multiply(multiplier, ...numbers) {
  return numbers.map(n => n * multiplier);
}
const factors = [2, 3, 4];
console.log(multiply(10, ...factors)); // [20, 30, 40]
```

## 剩余参数与arguments对象的区别

```javascript
function compare() {
  // arguments
  console.log(Array.isArray(arguments)); // false
  console.log(Object.prototype.toString.call(arguments)); // [object Arguments]

  // 剩余参数
  const rest = [...arguments];
  console.log(Array.isArray(rest)); // true
}

// arguments的限制：
// 1. 类数组，不是真正的数组
// 2. 箭头函数中没有arguments
// 3. 不能在严格模式与默认参数混用（旧规范）
function example(a, b = 2) {
  'use strict';
  // console.log(arguments); // 严格模式下与默认参数一起使用会报错
}
```

## 扩展运算符实现原理

数组的扩展运算符基于Iterator接口：

```javascript
// 等价实现
function spreadArray(iterable) {
  const items = [];
  const iterator = iterable[Symbol.iterator]();
  let next = iterator.next();
  while (!next.done) {
    items.push(next.value);
    next = iterator.next();
  }
  return items;
}

// 没有Iterator接口的对象不能展开
const obj = { a: 1, b: 2 };
// console.log(...obj); // TypeError: Found non-callable @@iterator

// 对象扩展运算符（ES2018）使用不同的机制——基于可枚举属性
```

## 常见陷阱

```javascript
// 1. 剩余参数必须是最后一个
// function bad(a, ...rest, b) {} // SyntaxError

// 2. 构造函数的剩余参数
class CustomArray extends Array {
  constructor(...args) {
    super(...args);
  }
}

// 3. 扩展运算符进行浅拷贝
const original = { nested: { value: 1 } };
const copy = { ...original };
copy.nested.value = 2;
console.log(original.nested.value); // 2 — 浅拷贝！

// 4. 对象扩展运算符只展开可枚举属性
const obj = { a: 1 };
Object.defineProperty(obj, 'b', { value: 2, enumerable: false });
console.log({ ...obj }); // { a: 1 }
```

## 解构中的剩余模式

```javascript
// 数组解构中的剩余模式
const [first, ...rest] = [1, 2, 3, 4];
console.log(first, rest); // 1 [2, 3, 4]

// 对象解构中的剩余模式
const { a, ...others } = { a: 1, b: 2, c: 3 };
console.log(a, others); // 1 { b: 2, c: 3 }

// 注意：解构中的剩余必须是最后一个
// const [...rest, last] = [1,2,3]; // SyntaxError

// 在函数参数解构中使用
function process({ name, ...details }) {
  console.log(name, details);
}
process({ name: 'Alice', age: 25, role: 'dev' });
// Alice { age: 25, role: 'dev' }
```

# ✅模板字符串有哪些高级用法？

# 典型回答

模板字符串（Template Literals）是ES6引入的字符串语法，使用反引号（\`）替代单引号或双引号。相比传统字符串，模板字符串提供了以下核心能力：

**基本特性：**

1. **嵌入式表达式**：`${expression}`语法嵌入任意JavaScript表达式
2. **多行字符串**：直接支持换行，无需`\n`拼接
3. **标签模板（Tagged Templates）**：通过自定义函数处理模板字符串

**高级用法：**
- 嵌套模板
- 条件表达式嵌入
- 函数调用嵌入
- 模板字符串作为函数参数
- 标签模板实现字符串转义、国际化、SQL构建等

# 扩展知识

## 嵌入式表达式详解

```javascript
const name = 'Alice';
const age = 25;

// 嵌入变量
console.log(`Name: ${name}`);

// 嵌入运算
console.log(`${name} is ${age > 18 ? 'adult' : 'minor'}`);

// 嵌入函数调用
const getUser = () => ({ name: 'Bob', role: 'admin' });
console.log(`User: ${getUser().name}, Role: ${getUser().role}`);

// 嵌入方法链
const items = [1, 2, 3];
console.log(`Sum: ${items.reduce((a, b) => a + b, 0)}`);

// 嵌套模板
const nested = `Outer ${`Inner ${name}`}`;
console.log(nested); // Outer Inner Alice
```

## 标签模板（Tagged Templates）

标签模板是模板字符串最强大的特性，允许用函数处理模板字符串：

```javascript
// 基本标签函数
function highlight(strings, ...values) {
  return strings.reduce((result, str, i) => {
    const value = values[i] ? `<strong>${values[i]}</strong>` : '';
    return result + str + value;
  }, '');
}

const user = 'Alice';
const role = 'admin';
const result = highlight`User ${user} has role ${role}`;
// "User <strong>Alice</strong> has role <strong>admin</strong>"
```

## 标签模板的实际应用

```javascript
// 1. SQL防注入
function escapeSQL(strings, ...values) {
  return strings.reduce((result, str, i) => {
    const sanitized = values[i] ? values[i].replace(/'/g, "''") : '';
    return result + str + sanitized;
  }, '');
}
const name = "O'Brien";
const query = escapeSQL`SELECT * FROM users WHERE name = '${name}'`;
// SELECT * FROM users WHERE name = 'O''Brien'

// 2. HTML转义
function htmlEscape(strings, ...values) {
  const escape = (str) => str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
  return strings.reduce((result, str, i) => {
    return result + str + (values[i] ? escape(values[i]) : '');
  }, '');
}

const userInput = '<script>alert("xss")</script>';
const safe = htmlEscape`<div>${userInput}</div>`;
console.log(safe); // <div>&lt;script&gt;alert("xss")&lt;/script&gt;</div>

// 3. 国际化（i18n）
function i18n(strings, ...values) {
  // 模拟语言包
  const translations = {
    'Hello': '你好',
    'Welcome': '欢迎'
  };
  return strings.reduce((result, str, i) => {
    const translated = translations[str.trim()] || str;
    return result + translated + (values[i] || '');
  }, '');
}
console.log(i18n`Hello, ${name}!`); // 你好, Alice!

// 4. 带样式的控制台输出
function styled(strings, ...values) {
  return strings.reduce((result, str, i) => {
    const style = values[i] ? `%c${values[i]}` : '';
    return result + str + style;
  }, '');
}
console.log(styled`Error: ${'red'} occurred`);
```

## 原始字符串（Raw Strings）

通过`String.raw`标签函数可以获取原始字符串（不处理转义字符）：

```javascript
// 普通模板字符串
console.log(`Hello\nWorld`);
// Hello
// World

// 原始字符串
console.log(String.raw`Hello\nWorld`);
// Hello\nWorld

// 实际应用：正则表达式
const regex = String.raw`\d+\.\d+`;
console.log(regex); // \d+\.\d+

// 文件路径
const path = String.raw`C:\Users\Alice\Documents`;
console.log(path); // C:\Users\Alice\Documents
```

## 自定义标签函数中获取原始字符串

```javascript
function logRaw(strings) {
  console.log('解析后的:', strings[0]);
  console.log('原始的:', strings.raw[0]);
}

logRaw`Hello\nWorld`;
// 解析后的: Hello
//            World
// 原始的: Hello\nWorld
```

## 模板字符串与性能

```javascript
// 模板字符串在运行时求值
const fn = (name) => `Hello, ${name}!`;
// 等价于：
const fn2 = (name) => 'Hello, ' + name + '!';

// 在V8引擎中，模板字符串的性能与字符串拼接相当或更优

// 避免在循环中创建复杂的模板
// 不推荐：
for (let i = 0; i < 1000; i++) {
  const message = `Item #${i}: ${getDetail(i)}`;
}

// 推荐：使用数组join
for (let i = 0; i < 1000; i++) {
  const message = ['Item #', i, ': ', getDetail(i)].join('');
}
```

## 模板字符串的限制

```javascript
// 不能直接引用自身
// const self = `${self}`; // ReferenceError

// 不能包含未转义的回引号
// const bad = `can't use \` directly`; // 需要转义：\`

// 三元运算符需要括号
const a = 1;
console.log(`value: ${a > 0 ? 'positive' : 'negative'}`); // 正确
// console.log(`value: ${a > 0 ? 'positive' : 'negative'}`); // 同样的效果

// 模板字符串中的表达式不能是语句
// console.log(`${if (true) { 'yes' }}`); // SyntaxError
```

## 最佳实践

- 使用模板字符串替代字符串拼接
- 复杂表达式前先计算，保持模板字符串可读性
- 利用标签模板处理需要对字符串做额外处理的场景
- 使用`String.raw`处理包含大量反斜杠的字符串

# ✅箭头函数中this为什么不会被改变？

# 典型回答

箭头函数中的this**不能被改变**，因为箭头函数**根本没有自己的this**。箭头函数定义时，它的this继承自**外层（词法作用域）的this**，与调用方式无关。

**根本原因：**
- 箭头函数没有 `[[ThisMode]]` 内部槽位（没有this绑定机制）
- 箭头函数不使用 `this` 的**动态绑定规则**（默认、隐式、显式、new）
- 箭头函数中的 `this` 标识符按**词法作用域**查找，就像普通变量一样

```javascript
// 箭头函数中的this就像普通变量一样按作用域链查找
const outer = {
  name: 'outer',
  arrowFn: () => {
    console.log(this.name); // this指向定义时的外层作用域
  }
};
```

**这意味着：**
1. call/apply/bind 无法改变箭头函数的this
2. new 无法与箭头函数配合使用
3. 箭头函数适合用在需要保留外层this的场景

# 扩展知识

## 箭头函数没有自己的this的底层原因

```javascript
// 普通函数的this由调用方式决定
function normalFunc() {
  console.log(this); // 指向调用者
}

// 箭头函数没有this绑定
const arrowFunc = () => {
  console.log(this); // 相当于访问外层作用域的this变量
};

// 在V8引擎中：
// 普通函数有独立的VariableMode中的this
// 箭头函数直接跳过this的创建，访问上层作用域的this

// 类似于以下代码的效果：
const _this = this;  // 捕获外层的this
const arrowFunc2 = function() {
  console.log(_this);
};
```

## 词法作用域 vs 动态作用域

```javascript
// 箭头函数使用词法作用域（定义时确定）
// 普通函数使用动态作用域（调用时确定）

const thisValue = 'global';

const obj = {
  thisValue: 'obj',

  // 普通函数：调用时确定this
  normal() {
    console.log(this.thisValue); // 取决于调用方式
  },

  // 箭头函数：定义时确定this
  arrow: () => {
    console.log(this.thisValue); // 继承定义时的外层作用域
  }
};

// 测试
obj.normal(); // 'obj' — 隐式绑定，this指向obj
obj.arrow();  // 'global' — 定义时this指向全局

// 惊人的对比
const extractedNormal = obj.normal;
const extractedArrow = obj.arrow;

extractedNormal(); // 'global' — 默认绑定
extractedArrow();  // 'global' — 定义时已确定
```

## 多层嵌套的this分析

```javascript
const global = 'global';

function outerFunc() {
  // 这里this由调用方式决定
  console.log('outerFunc this:', this);

  const innerArrow = () => {
    // 继承outerFunc的this
    console.log('innerArrow this:', this);
  };

  const innerNormal = function() {
    // 独立this，由调用方式决定
    console.log('innerNormal this:', this);
  };

  innerArrow();  // 继承outerFunc的this
  innerNormal(); // 默认绑定（严格模式undefined）
}

outerFunc.call({ name: 'outer context' });
// outerFunc this: { name: 'outer context' }
// innerArrow this: { name: 'outer context' } — 继承
// innerNormal this: window/undefined — 默认绑定
```

## 箭头函数与闭包中的this

```javascript
// 闭包中的this陷阱（普通函数）
function Timer() {
  this.seconds = 0;

  // 普通函数：每个回调都有自己的this
  setInterval(function() {
    // this指向全局对象（浏览器中的window）
    this.seconds++; // 不会修改Timer的seconds
    console.log(this.seconds); // NaN
  }, 1000);
}

// 传统解决方案
function TimerFixed() {
  this.seconds = 0;
  const self = this;  // 用变量保存this

  setInterval(function() {
    self.seconds++; // 通过闭包访问
  }, 1000);
}

// 箭头函数解决方案
function TimerWithArrow() {
  this.seconds = 0;

  setInterval(() => {
    // 箭头函数继承Timer的this
    this.seconds++;
    console.log(this.seconds);
  }, 1000);
}
```

## 箭头函数中的call/apply/bind

```javascript
const arrow = () => {
  console.log('this:', this);
};

// 所有尝试改变this的操作都无效
arrow.call({ x: 1 });        // this: 外层this
arrow.apply({ x: 1 });       // this: 外层this
const bound = arrow.bind({ x: 1 });
bound();                     // this: 外层this

// 验证call/apply/bind确实无法改变
const obj = {
  name: 'obj',
  arrowFn: () => {
    console.log(this.name);
  }
};

obj.arrowFn();                       // undefined
obj.arrowFn.call({ name: 'new' });   // undefined
obj.arrowFn.apply({ name: 'new' });  // undefined
obj.arrowFn.bind({ name: 'new' })(); // undefined
```

## 箭头函数中this的常见误解

```javascript
// 误解1：箭头函数的this指向定义时的对象
const obj = {
  name: 'obj',
  arrow: () => {
    console.log(this.name);
  }
};
// 实际上箭头函数的this不指向obj，指向外层作用域

// 误解2：箭头函数的this是固定的
// 实际上箭头函数的this是在定义时确定的，之后不会变化
// 但不同执行上下文中的箭头函数有不同的this

// 误解3：箭头函数中的this与function中的this没有区别
// 错误！两者的绑定规则完全不同

// 误解4：对象的简写方法等同于箭头函数
const obj2 = {
  method() {},  // 这是方法简写，不是箭头函数
  arrow: () => {} // 这是箭头函数
};
// method有自己的this；arrow没有自己的this
```

## 在class中使用箭头函数

```javascript
class MyClass {
  name = 'MyClass';

  // 方法定义在原型上
  normalMethod() {
    console.log(this.name);
  }

  // 箭头函数作为属性，定义在实例上
  arrowMethod = () => {
    console.log(this.name);
  }
}

const instance = new MyClass();

// 作为方法调用
instance.normalMethod(); // 'MyClass'
instance.arrowMethod();  // 'MyClass'

// 提取方法后调用
const normal = instance.normalMethod;
const arrow = instance.arrowMethod;

normal(); // undefined — this丢失
arrow();  // 'MyClass' — this由定义时的实例确定

// 这就是React类组件中使用箭头函数的原因
class ReactComponent {
  constructor() {
    this.state = { count: 0 };
    // 如果不绑定，事件处理中的this会丢失
    this.handleClick = this.handleClick.bind(this);
    // 或者用箭头函数
    this.handleClickArrow = () => {
      this.setState(...);
    };
  }
  handleClick() { /* this需要绑定 */ }
}
```

## 总结：箭头函数this不可改变的原因

1. **没有[[ThisMode]]**：箭头函数在创建时不绑定this
2. **词法作用域**：this标识符按词法作用域链查找
3. **没有[[Construct]]**：不能作为构造函数
4. **设计目的**：解决回调函数中this丢失的问题
5. **无法覆盖**：箭头函数没有this绑定，所以任何显式绑定都无效

**什么时候使用箭头函数：**
- 需要保留外层this的回调（定时器、事件监听、Promise链）
- 函数式编程场景
- 不希望this被动态绑定的情况

**什么时候避免使用箭头函数：**
- 对象方法（需要动态this）
- 原型方法
- 构造函数
- 需要动态绑定this的场景

# ✅箭头函数和普通函数的区别是什么？箭头函数的this指向如何确定？

# 典型回答

箭头函数是ES6引入的一种更简洁的函数语法，与普通函数有多个关键区别：

**主要区别：**

| 特性 | 普通函数 | 箭头函数 |
|------|---------|---------|
| this绑定 | 动态绑定，取决于调用方式 | 词法绑定，继承外层作用域的this |
| 构造函数 | 可以作为构造函数，使用new | 不能作为构造函数，没有[[Construct]] |
| arguments对象 | 拥有自己的arguments | 没有arguments，需用剩余参数替代 |
| prototype属性 | 有prototype属性 | 没有prototype属性 |
| 语法 | function关键字声明 | => 箭头语法 |
| 重复参数名 | 非严格模式下允许 | 不允许 |
| 用作方法 | 适合对象方法 | 不适合（this指向外层） |

**箭头函数的this指向如何确定：**

箭头函数没有自己的this，它的this继承自**外层（词法作用域）的this**，在定义时确定，而不是在调用时确定。箭头函数的this一旦确定，即使通过call/apply/bind也无法改变。

# 扩展知识

## 箭头函数不能用作构造函数的深层原因

箭头函数没有`[[Construct]]`内部方法，也没有`prototype`属性。当使用`new`调用时，JavaScript引擎会尝试调用`[[Construct]]`，但箭头函数不存在这个方法，因此抛出错误：

```javascript
const Fn = () => {};
// new Fn(); // TypeError: Fn is not a constructor

function NormalFn() {}
console.log(NormalFn.prototype); // {constructor: ƒ}
console.log(Fn.prototype);       // undefined
```

## 箭头函数中this的绑定机制

```javascript
const obj = {
  name: 'Alice',
  normalFunc: function() {
    console.log(this.name);
  },
  arrowFunc: () => {
    console.log(this.name);
  }
};

obj.normalFunc(); // 'Alice' — this指向obj
obj.arrowFunc();  // undefined — this指向全局（或undefined在严格模式下）

// 更复杂的嵌套场景
const outer = {
  name: 'outer',
  inner: {
    name: 'inner',
    normal: function() {
      return function() {
        console.log(this.name);
      };
    },
    arrow: function() {
      return () => {
        console.log(this.name);
      };
    }
  }
};

outer.inner.normal()(); // undefined — 普通匿名函数this指向全局
outer.inner.arrow()();  // 'inner' — 箭头函数this继承自outer.inner.arrow的this
```

## call/apply/bind无法改变箭头函数this

```javascript
const arrow = () => console.log(this);
const normal = function() { console.log(this); };

arrow.call({ x: 1 });   // 仍然是外层的this
normal.call({ x: 1 });  // { x: 1 }

const boundArrow = arrow.bind({ x: 1 });
boundArrow();            // 仍然是外层的this
```

## 没有arguments对象的替代方案

```javascript
function normal() {
  console.log(arguments[0], arguments[1]);
}

const arrow = (...args) => {
  console.log(args[0], args[1]);
};

normal(1, 2);  // 1 2
arrow(1, 2);   // 1 2

// 注意：如果箭头函数外层是普通函数，可以访问外层的arguments
function wrapper() {
  const arrow = () => console.log(arguments[0]);
  arrow();
}
wrapper(42);   // 42
```

## 不适合使用箭头函数的场景

1. **对象方法**：需要this指向对象本身时
2. **原型方法**：需要this指向实例时
3. **事件监听器**：需要this指向触发事件的元素时
4. **需要动态绑定this**：什么时候调用不确定

```javascript
// 错误示例
const counter = {
  count: 0,
  increment: () => { this.count++; }  // this指向外层，不是counter
};

// DOM事件中
button.addEventListener('click', () => {
  this.textContent = 'Clicked';  // this指向window，不是button
});
```

## 适合使用箭头函数的场景

1. **回调函数**：setTimeout、Promise链、数组方法等
2. **函数式编程**：map、filter、reduce等
3. **需要保留外层this**：在嵌套函数中避免`var self = this`

# ✅解构赋值的原理和应用场景有哪些？

# 典型回答

解构赋值是ES6引入的一种语法，允许从数组或对象中提取值，按照对应模式赋给变量。其本质是**模式匹配**，即等号左边的模式与右边的数据结构匹配，提取对应位置的值。

**解构赋值的原理：**

- **数组解构**：基于**迭代器（Iterator）**协议，通过迭代器依次取值
- **对象解构**：基于属性键匹配，查找同名属性并赋值

**主要应用场景：**

- 交换变量值
- 从函数返回多个值
- 函数参数解构
- 解析后端API返回的数据
- 变量声明简化
- 嵌套数据结构提取
- 默认值处理

# 扩展知识

## 数组解构详解

```javascript
// 基本解构
const [a, b, c] = [1, 2, 3];
console.log(a, b, c); // 1 2 3

// 跳过某些元素
const [, , third] = [1, 2, 3];
console.log(third); // 3

// 剩余模式
const [head, ...tail] = [1, 2, 3, 4];
console.log(head); // 1
console.log(tail); // [2, 3, 4]

// 默认值（当解构的值为undefined时触发）
const [x = 10, y = 20] = [1];
console.log(x, y); // 1 20

// 交换变量
let [p, q] = [1, 2];
[p, q] = [q, p];
console.log(p, q); // 2 1

// 嵌套数组解构
const [first, [second, third]] = [1, [2, 3]];
console.log(first, second, third); // 1 2 3
```

## 对象解构详解

```javascript
// 基本解构
const { name, age } = { name: 'Alice', age: 25 };
console.log(name, age); // Alice 25

// 重命名
const { name: userName, age: userAge } = { name: 'Bob', age: 30 };
console.log(userName, userAge); // Bob 30

// 默认值
const { city = 'Beijing', country } = { country: 'China' };
console.log(city, country); // Beijing China

// 嵌套解构
const user = {
  id: 1,
  profile: {
    name: 'Alice',
    address: { city: 'Shanghai', district: 'Pudong' }
  }
};
const { profile: { address: { city } } } = user;
console.log(city); // Shanghai

// 剩余属性（ES2018）
const { a: x, ...rest } = { a: 1, b: 2, c: 3 };
console.log(x, rest); // 1 { b: 2, c: 3 }
```

## 函数参数解构

```javascript
// 对象参数解构
function createUser({ name, age = 18, role = 'user' }) {
  console.log(`${name}, ${age}, ${role}`);
}
createUser({ name: 'Alice', age: 25 }); // Alice, 25, user

// 数组参数解构
function sum([a, b, c]) {
  return a + b + c;
}
console.log(sum([1, 2, 3])); // 6

// 解构与剩余参数结合
function logUser({ name, ...details }) {
  console.log(name, details);
}
logUser({ name: 'Alice', age: 25, city: 'Beijing' });
// Alice { age: 25, city: 'Beijing' }
```

## 解构的常见应用

```javascript
// 1. 从API响应中提取数据
const response = {
  data: { users: [{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }] },
  status: 200,
  pagination: { page: 1, total: 10 }
};
const { data: { users }, pagination: { total } } = response;

// 2. 遍历Map结构
const map = new Map();
map.set('name', 'Alice');
map.set('age', 25);
for (const [key, value] of map) {
  console.log(`${key}: ${value}`);
}

// 3. 处理函数返回的多个值
function getMinMax(arr) {
  return [Math.min(...arr), Math.max(...arr)];
}
const [min, max] = getMinMax([3, 1, 4, 1, 5, 9]);

// 4. 动态属性解构
const prop = 'name';
const { [prop]: value } = { name: 'Alice' };
console.log(value); // Alice

// 5. 导入模块的特定部分
// import { readFile, writeFile } from 'fs';

// 6. 解构正则匹配结果
const url = 'https://example.com/path?page=1';
const [, protocol, domain] = /^(https?):\/\/([^/]+)/.exec(url) || [];
console.log(protocol, domain); // https example.com
```

## 解构的原理：Iterator接口

数组解构之所以能工作，是因为数组实现了Iterator接口：

```javascript
// 以下写法等效于数组解构
const arr = [1, 2, 3];
const iterator = arr[Symbol.iterator]();
const a = iterator.next().value; // 1
const b = iterator.next().value; // 2
const c = iterator.next().value; // 3

// 实现了Iterator接口的对象也可以解构
class Range {
  constructor(start, end) {
    this.start = start;
    this.end = end;
  }
  [Symbol.iterator]() {
    let current = this.start;
    const end = this.end;
    return {
      next() {
        return current <= end
          ? { value: current++, done: false }
          : { done: true };
      }
    };
  }
}
const [first, second, third] = new Range(10, 20);
console.log(first, second, third); // 10 11 12
```

## 解构的注意事项

- **声明与赋值分离**：解构赋值中，变量已声明时需用括号包裹对象解构
- **null/undefined不能解构**：对null或undefined解构会抛出TypeError
- **解构失败返回undefined**：模式不匹配时，变量值为undefined
- **不要过度解构**：深度嵌套的解构会降低可读性

# ✅闭包是什么？有什么应用场景和缺点？

# 典型回答

**闭包（Closure）** 是指一个函数"记忆"并访问其词法作用域的能力，即使该函数在其词法作用域之外执行。闭包是**函数**和**创建该函数的环境**的组合。

```javascript
function outer() {
  const message = 'Hello';
  function inner() {
    console.log(message);  // inner引用了outer的变量
  }
  return inner;
}

const closure = outer();
closure(); // 'Hello' — 闭包维持了对message的引用
```

**闭包的核心特性：**
- 内部函数可以访问外部函数的变量
- 外部函数的变量不会被垃圾回收（只要内部函数存在）
- 每次调用外部函数都会创建新的闭包

**常见应用场景：**

| 场景 | 说明 |
|------|------|
| 数据私有化 | 模拟私有变量和方法 |
| 柯里化 | 将多参数函数转换为单参数函数链 |
| 函数工厂 | 创建带有预设参数的函数 |
| 事件处理 | 绑定点击事件时保持状态 |
| 防抖节流 | 保存定时器状态 |
| 模块模式 | 实现模块化封裝 |
| 高阶函数 | 函数作为返回值 |

**闭包的缺点：**
- 内存占用：闭包阻止垃圾回收，可能导致内存泄漏
- 性能开销：多层闭包增加了作用域链查找的层次
- 调试困难：闭包中的变量在调试时不易追踪

# 扩展知识

## 闭包的工作原理

```javascript
// 每个函数在执行时都会创建[[Scopes]]属性
function outer() {
  const x = 10;
  const y = 20;
  function inner() {
    return x + y;  // inner通过作用域链访问x和y
  }
  return inner;
}

const fn = outer();
console.log(fn()); // 30

// 可视化表示
// fn.[[Scopes]] = [outer函数的变量对象, 全局变量对象]
// 即使outer执行完毕，outer的作用域对象仍然被inner引用，不会被GC回收
```

## 闭包与循环

```javascript
// 经典问题：闭包捕获的是变量的引用而非值
for (var i = 0; i < 5; i++) {
  setTimeout(function() {
    console.log(i); // 5, 5, 5, 5, 5
  }, 100);
}

// 解决方案1：IIFE创建独立作用域
for (var i = 0; i < 5; i++) {
  (function(j) {
    setTimeout(function() {
      console.log(j); // 0, 1, 2, 3, 4
    }, 100);
  })(i);
}

// 解决方案2：使用let（块级作用域）
for (let i = 0; i < 5; i++) {
  setTimeout(function() {
    console.log(i); // 0, 1, 2, 3, 4
  }, 100);
}

// 解决方案3：使用闭包工厂函数
function createCallback(i) {
  return function() {
    console.log(i);
  };
}
for (var i = 0; i < 5; i++) {
  setTimeout(createCallback(i), 100);
}
```

## 模拟私有变量

```javascript
// 使用闭包实现私有变量
function createCounter() {
  let count = 0;  // 私有变量

  return {
    increment() {
      count++;
      return count;
    },
    decrement() {
      count--;
      return count;
    },
    getCount() {
      return count;
    }
  };
}

const counter = createCounter();
console.log(counter.increment()); // 1
console.log(counter.increment()); // 2
console.log(counter.getCount());  // 2
// console.log(counter.count);    // undefined — 外部无法直接访问

// 使用Symbol实现类似效果
const _count = Symbol('count');
class Counter {
  constructor() {
    this[_count] = 0;
  }
  increment() { return ++this[_count]; }
}
// 但Object.getOwnPropertySymbols()仍然可以获取
```

## 模块模式

```javascript
// 闭包实现模块化
const myModule = (function() {
  // 私有变量
  const privateData = [];
  let id = 0;

  // 私有函数
  function validate(item) {
    return item !== null && item !== undefined;
  }

  // 公共API
  return {
    add(item) {
      if (validate(item)) {
        privateData.push({ id: id++, value: item });
        return true;
      }
      return false;
    },
    getAll() {
      return [...privateData];
    },
    getById(itemId) {
      return privateData.find(item => item.id === itemId);
    },
    remove(itemId) {
      const index = privateData.findIndex(item => item.id === itemId);
      if (index !== -1) {
        privateData.splice(index, 1);
        return true;
      }
      return false;
    },
    get count() {
      return privateData.length;
    }
  };
})();

myModule.add('item1');
console.log(myModule.count); // 1
console.log(myModule.getAll()); // [{ id: 0, value: 'item1' }]
```

## 函数柯里化

```javascript
// 闭包实现柯里化
function curry(fn) {
  return function curried(...args) {
    if (args.length >= fn.length) {
      return fn.apply(this, args);
    }
    return function(...args2) {
      return curried.apply(this, args.concat(args2));
    };
  };
}

// 普通函数
function sum(a, b, c) {
  return a + b + c;
}

const curriedSum = curry(sum);
console.log(curriedSum(1)(2)(3));   // 6
console.log(curriedSum(1, 2)(3));   // 6
console.log(curriedSum(1)(2, 3));   // 6

// 实际应用：日志函数
function log(level) {
  return function(message) {
    console.log(`[${level.toUpperCase()}] ${message}`);
  };
}

const info = log('info');
const warn = log('warn');
const error = log('error');

info('系统启动');   // [INFO] 系统启动
error('连接失败');  // [ERROR] 连接失败
```

## 防抖和节流

```javascript
// 防抖：多次触发只执行最后一次
function debounce(fn, delay) {
  let timer = null;  // 闭包保存timer
  return function(...args) {
    const context = this;
    clearTimeout(timer);
    timer = setTimeout(() => {
      fn.apply(context, args);
    }, delay);
  };
}

// 节流：限制执行频率
function throttle(fn, limit) {
  let inThrottle = false;  // 闭包保存状态
  return function(...args) {
    const context = this;
    if (!inThrottle) {
      fn.apply(context, args);
      inThrottle = true;
      setTimeout(() => { inThrottle = false; }, limit);
    }
  };
}

// 使用
const handleScroll = throttle(() => {
  console.log('滚动事件处理');
}, 200);
window.addEventListener('scroll', handleScroll);
```

## 闭包的内存管理

```javascript
// 不必要的闭包导致内存泄漏
function createLargeArray() {
  const largeArray = new Array(1000000).fill('data');

  return function() {
    console.log(largeArray.length);
    // largeArray无法被GC回收，因为闭包一直引用它
  };
}

const fn = createLargeArray();
// 即使fn只用一次，largeArray依然占用内存

// 手动解除引用
fn = null;  // 闭包被释放，largeArray可被GC回收

// 优化：只保留需要的数据
function createEfficient() {
  const largeArray = new Array(1000000).fill('data');
  const length = largeArray.length;  // 只保留需要的值

  return function() {
    console.log(length);
  };
}
```

## 闭包与作用域链的交互

```javascript
// 多层嵌套闭包共享同一作用域的问题
function createFunctions() {
  const functions = [];
  for (var i = 0; i < 5; i++) {
    functions.push(function() {
      console.log(i);
    });
  }
  return functions;
}
const fns = createFunctions();
fns[0](); // 5 — 所有函数共享同一个i
fns[1](); // 5

