  const functions = [];
  for (var i = 0; i < 5; i++) {
    (function(j) {
      functions.push(function() {
        console.log(j);
      });
    })(i);
  }
  return functions;
}
```

## React Hooks中的闭包陷阱

```javascript
// React函数组件中常见的闭包问题
